    const [customStandards, setCustomStandards] = useState<StandardsData>(STANDARDS_DATA);
    const [standardKey, setStandardKey] = useState<string>("ISO 9001:2015");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>({ company: "", smo: "", department: "", interviewee: "", auditor: "", type: "" });
    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [pastedImages, setPastedImages] = useState<File[]>([]);

    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [finalReportText, setFinalReportText] = useState<string | null>(null);
    const [layoutMode, setLayoutMode] = useState('evidence' as LayoutMode);

    // Loading Flags
    const [isOcrLoading, setIsOcrLoading] = useState(false);
    const [isAnalyzeLoading, setIsAnalyzeLoading] = useState(false);
    const [currentAnalyzingClause, setCurrentAnalyzingClause] = useState<string>(""); 
    const [isReportLoading, setIsReportLoading] = useState(false);

    const [logoKey, setLogoKey] = useState(0);

    // Fluid Tab State
    const [tabStyle, setTabStyle] = useState({ left: 0, width: 0, opacity: 0, color: '' });
    const tabsRef = useRef<(HTMLButtonElement | null)[]>([]);
    const tabsContainerRef = useRef<HTMLDivElement>(null); 

    const tabsList = [
        { id: 'evidence', label: '1. Evidence', icon: 'ScanText', colorClass: 'bg-blue-500', textClass: 'text-blue-600', borderClass: 'border-blue-500', bgSoft: 'bg-blue-50 dark:bg-blue-900/10' }, 
        { id: 'findings', label: '2. Findings', icon: 'Wand2', colorClass: 'bg-purple-500', textClass: 'text-purple-600', borderClass: 'border-purple-500', bgSoft: 'bg-purple-50 dark:bg-purple-900/10' }, 
        { id: 'report', label: '3. Report', icon: 'FileText', colorClass: 'bg-emerald-500', textClass: 'text-emerald-600', borderClass: 'border-emerald-500', bgSoft: 'bg-emerald-50 dark:bg-emerald-900/10' }
    ];
    const currentTabConfig = tabsList.find(t => t.id === layoutMode) || tabsList[0];

    const fileInputRef = useRef<HTMLInputElement>(null);
    const evidenceTextareaRef = useRef<HTMLTextAreaElement>(null);
    const findingsContainerRef = useRef<HTMLDivElement>(null);

    const allStandards = { ...STANDARDS_DATA, ...customStandards };
    const hasEvidence = evidence.trim().length > 0 || pastedImages.length > 0;
    const isReadyForAnalysis = !isAnalyzeLoading && selectedClauses.length > 0 && hasEvidence;

    // --- UTILS ---
    const insertTextAtCursor = (textToInsert: string) => {
        if (evidenceTextareaRef.current) {
            const textarea = evidenceTextareaRef.current;
            const start = textarea.selectionStart;
            const end = textarea.selectionEnd;
            const newValue = evidence.substring(0, start) + textToInsert + evidence.substring(end);
            setEvidence(newValue);
            if (layoutMode !== 'evidence') setLayoutMode('evidence');
            setTimeout(() => {
                if (evidenceTextareaRef.current) {
                    evidenceTextareaRef.current.focus();
                    evidenceTextareaRef.current.setSelectionRange(start + textToInsert.length, start + textToInsert.length);
                }
            }, 100);
        } else {
            setEvidence(prev => prev + "\n" + textToInsert);
            if (layoutMode !== 'evidence') setLayoutMode('evidence');
        }
    };

    // --- EFFECTS ---
    useEffect(() => {
        const storedScale = localStorage.getItem('iso_font_scale');
        if (storedScale) setFontSizeScale(parseFloat(storedScale));

        loadSessionData();
        const savedDarkMode = localStorage.getItem('iso_dark_mode');
        if (savedDarkMode !== null) setIsDarkMode(savedDarkMode === 'true');
        else setIsDarkMode(true); 

        if (window.innerWidth < 768) setIsSidebarOpen(false);
    }, []);

    useEffect(() => {
        const updateTabs = () => {
            const activeIndex = tabsList.findIndex(t => t.id === layoutMode);
            const el = tabsRef.current[activeIndex];
            if (el) setTabStyle({ left: el.offsetLeft, width: el.offsetWidth, opacity: 1, color: tabsList[activeIndex].colorClass });
        };
        updateTabs();
        const t = setTimeout(updateTabs, 50);
        const observer = new ResizeObserver(() => updateTabs());
        if (tabsContainerRef.current) observer.observe(tabsContainerRef.current);
        return () => { clearTimeout(t); observer.disconnect(); };
    }, [layoutMode, sidebarWidth, fontSizeScale]); 

    useEffect(() => {
        if (smartExport.exportState.isFinished && smartExport.exportState.isOpen) {
            smartExport.downloadExportFile(standardKey, auditInfo);
        }
    }, [smartExport.exportState.isFinished]);

    useEffect(() => {
        if (layoutMode === 'findings' && findingsContainerRef.current) {
            findingsContainerRef.current.scrollTop = findingsContainerRef.current.scrollHeight;
        }
    }, [analysisResult]);

    const loadSessionData = () => {
        try {
            const savedAuditInfo = localStorage.getItem("iso_audit_info");
            const savedEvidence = localStorage.getItem("iso_evidence");
            const savedStandardKey = localStorage.getItem("iso_standard_key");
            const savedSelectedClauses = localStorage.getItem("iso_selected_clauses");
            const savedTemplate = localStorage.getItem('iso_report_template');
            const savedTemplateName = localStorage.getItem('iso_report_template_name');

            if (savedAuditInfo) setAuditInfo(JSON.parse(savedAuditInfo));
            if (savedEvidence && savedEvidence.trim() !== '') setEvidence(savedEvidence);
            if (savedStandardKey) setStandardKey(savedStandardKey);
            if (savedSelectedClauses) setSelectedClauses(JSON.parse(savedSelectedClauses));
            if (savedTemplate) setReportTemplate(savedTemplate);
            if (savedTemplateName) setTemplateFileName(savedTemplateName);
        } catch (e) { console.error("Failed to load session data", e); }
    };

    useEffect(() => {
        if (isDarkMode) document.body.classList.add('dark'); else document.body.classList.remove('dark');
        localStorage.setItem('iso_dark_mode', String(isDarkMode));
    }, [isDarkMode]);

    useEffect(() => {
        document.documentElement.style.setProperty('--font-scale', fontSizeScale.toString());
        localStorage.setItem('iso_font_scale', fontSizeScale.toString());
    }, [fontSizeScale]);

    useEffect(() => { localStorage.setItem("iso_audit_info", JSON.stringify(auditInfo)); }, [auditInfo]);
    useEffect(() => { localStorage.setItem("iso_evidence", evidence); }, [evidence]);
    useEffect(() => { localStorage.setItem("iso_standard_key", standardKey); }, [standardKey]);
    useEffect(() => { localStorage.setItem("iso_selected_clauses", JSON.stringify(selectedClauses)); }, [selectedClauses]);
    useEffect(() => {
        localStorage.setItem('iso_report_template', reportTemplate);
        localStorage.setItem('iso_report_template_name', templateFileName);
    }, [reportTemplate, templateFileName]);

    // --- HANDLERS ---
    const handleNewSession = () => {
        if (window.confirm("Start new session? Current work will be cleared.")) {
            setAuditInfo({ company: "", smo: "", department: "", interviewee: "", auditor: "", type: "" });
            setSelectedClauses([]);
            setEvidence(INITIAL_EVIDENCE);
            setPastedImages([]);
            setAnalysisResult(null);
            setSelectedFindings({});
            setFinalReportText(null);
            setLayoutMode('evidence');
            setAiError(null);
        }
    };

    const handleUpdateStandard = (updated: Standard) => setCustomStandards(prev => ({ ...prev, [standardKey]: updated }));
    const handleResetStandard = (key: string) => { setCustomStandards(prev => { const next = { ...prev }; delete next[key]; return next; }); };

    const loadStressTestData = () => {
        setAuditInfo({ company: "TechCorp Global", smo: "TC-2024-ISO-001", department: "IT Ops", interviewee: "John Smith", auditor: "Trung Dang", type: "Stage 2" });
        setStandardKey("ISO 27001:2022 (ISMS)");
        setSelectedClauses(["5.1", "6.1.2", "A.5.9", "9.2"]);
        setEvidence(`AUDIT EVIDENCE TEST...\n[5.1] Leadership committed. Policy approved.\n[A.5.9] Assets reviewed. 5 laptops checked. 1 missing tag.`);
        setToastMsg("Stress Test Data Loaded!");
        setLayoutMode('evidence');
    };

    const handleRecall = () => { loadSessionData(); setToastMsg("Session Recalled Successfully"); };

    const handleTemplateUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        setTemplateFileName(file.name);
        if (file.name.endsWith('.docx')) {
            const arrayBuffer = await file.arrayBuffer();
            mammoth.extractRawText({ arrayBuffer }).then((result: any) => setReportTemplate(result.value)).catch((err: any) => console.error(err));
        } else {
            const reader = new FileReader();
            reader.onload = (re) => setReportTemplate(re.target?.result as string);
            reader.readAsText(file);
        }
    };

    const handlePaste = (e: React.ClipboardEvent) => {
        const items = e.clipboardData.items;
        const newImages: File[] = [];
        for (let i = 0; i < items.length; i++) {
            if (items[i].type.indexOf("image") !== -1) {
                const blob = items[i].getAsFile();
                if (blob) newImages.push(blob);
            }
        }
        if (newImages.length > 0) setPastedImages(prev => [...prev, ...newImages]);
    };

    const handleUpdateFinding = (index: number, field: keyof AnalysisResult, value: string) => {
        setAnalysisResult(prev => {
            if (!prev) return null;
            const newArr = [...prev];
            newArr[index] = { ...newArr[index], [field]: value };
            return newArr;
        });
    };

    // --- AI HANDLERS ---
    const handleAnalyze = async () => {
        if (!hasEvidence || selectedClauses.length === 0) return;
        setIsAnalyzeLoading(true); setAiError(null); setAnalysisResult([]); setLayoutMode('findings'); setLoadingMessage("Initializing AI Auditor...");

        try {
            const scopeClauses = allStandards[standardKey].groups.flatMap(g => g.clauses).filter(c => selectedClauses.includes(c.id));

            for (let i = 0; i < scopeClauses.length; i++) {
                const clause = scopeClauses[i];
                setCurrentAnalyzingClause(clause.code); setLoadingMessage(`Analyzing Clause ${clause.code}...`);

                const prompt = `Act as an ISO Lead Auditor. Evaluate compliance for this SINGLE clause:
                [${clause.code}] ${clause.title}: ${clause.description}
                CONTEXT: ${auditInfo.type} for ${auditInfo.company}.
                RAW EVIDENCE: """ ${evidence} """
                Return a JSON Array with exactly ONE object containing: clauseId (must be "${clause.id}"), status (COMPLIANT, NC_MAJOR, NC_MINOR, OFI), reason, suggestion, evidence, conclusion_report (concise).`;

                try {
                    const resultStr = await gemini.executeWithSmartFailover(async (key, model) => {
                        return await generateAnalysis(prompt, `Output JSON array only.`, key, model);
                    });
                    const chunkResult = cleanAndParseJSON(resultStr || "");
                    if (chunkResult && Array.isArray(chunkResult) && chunkResult.length > 0) {
                        const resultItem = chunkResult[0];
                        resultItem.clauseId = clause.id;
                        setAnalysisResult(prev => {
                            const prevSafe = prev || [];
                            if (prevSafe.find(r => r.clauseId === resultItem.clauseId)) return prevSafe;
                            setSelectedFindings(sel => ({...sel, [resultItem.clauseId]: true}));
                            return [...prevSafe, resultItem];
                        });
                    }
                } catch (innerError: any) {
                    if (innerError.message === "ALL_RESOURCES_EXHAUSTED" || innerError.message === "ALL_KEYS_EXHAUSTED") throw innerError; 
                    console.error(`Failed to analyze clause ${clause.code}`, innerError);
                }
                await new Promise(r => setTimeout(r, 200));
            }
        } catch (e: any) { 
            if (e.message === "ALL_KEYS_EXHAUSTED" || e.message === "ALL_RESOURCES_EXHAUSTED") {
                setAiError("System Overload: All API Keys and Model Backups are exhausted.");
                setShowSettingsModal(true); 
            } else setAiError(e.message || "Analysis Failed");
        } finally { 
            setIsAnalyzeLoading(false); setCurrentAnalyzingClause(""); setLoadingMessage("");
        }
    };

    const handleGenerateReport = async () => {
        if (!analysisResult) return;
        setIsReportLoading(true); setLayoutMode('report'); setAiError(null);
        setLoadingMessage(!!reportTemplate ? `Analyzing Template...` : "Synthesizing Report...");

        try {
             const acceptedFindings = analysisResult.filter(r => selectedFindings[r.clauseId]);
             let prompt = !!reportTemplate ? `ROLE: ISO Lead Auditor. TASK: Follow TEMPLATE structure strictly.\nTEMPLATE:\n"""${reportTemplate}"""\nDATA: Context: ${JSON.stringify(auditInfo)}, Findings: ${JSON.stringify(acceptedFindings)}` : `GENERATE FINAL REPORT. DATA: ${JSON.stringify(auditInfo)}. FINDINGS: ${JSON.stringify(acceptedFindings)}.`;
             const text = await gemini.executeWithSmartFailover(async (key, model) => await generateTextReport(prompt, "Expert ISO Report Compiler.", key, model));
             setFinalReportText(text || "");
        } catch (e: any) { 
            if (e.message === "ALL_KEYS_EXHAUSTED" || e.message === "ALL_RESOURCES_EXHAUSTED") {
                setAiError("API Quota Exceeded during report generation."); setShowSettingsModal(true);
            } else setAiError(e.message || "Report Generation Failed"); 
        } finally { setIsReportLoading(false); setLoadingMessage(""); }
    };

    const handleOcrUpload = async () => {
        if (pastedImages.length === 0) return;
        setIsOcrLoading(true); setAiError(null);
        try {
            const promises = pastedImages.map(async (file) => {
                const b64 = await fileToBase64(file);
                return await gemini.executeWithSmartFailover(async (key, model) => await generateOcrContent("Extract text accurately.", b64, file.type, key, model));
            });
            const results = await Promise.all(promises);
            insertTextAtCursor(results.join('\n\n'));
            setPastedImages([]);
        } catch (e: any) { setAiError(e.message || "OCR Processing Failed"); } finally { setIsOcrLoading(false); }
    };

    const handleDragOver = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(true); };
    const handleDrop = (e: React.DragEvent) => {
        e.preventDefault(); setIsDragging(false);
        const files = Array.from(e.dataTransfer.files);
        if (files.length > 0) setPastedImages(prev => [...prev, ...files]);
    };

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if ((e.metaKey || e.ctrlKey) && e.key === 'k') { e.preventDefault(); setIsCmdPaletteOpen(prev => !prev); }
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, []);

    const commandActions = useMemo(() => {
        const actions: any[] = [
            { label: "Analyze Compliance", desc: "Start AI analysis", icon: "Wand2", shortcut: "AI", action: handleAnalyze },
            { label: "Toggle Dark Mode", desc: `Switch to ${isDarkMode ? 'Light' : 'Dark'}`, icon: isDarkMode ? "Sun" : "Moon", action: () => setIsDarkMode(!isDarkMode) },
            { label: "Generate Report", desc: "Synthesize final report", icon: "FileText", action: handleGenerateReport },
            { label: "Export Notes", desc: "Download findings", icon: "Download", action: () => {
                 const reportTxt = analysisResult?.filter(r => selectedFindings[r.clauseId]).map(r => `[${r.status}] Clause ${r.clauseId}: ${r.conclusion_report}`).join('\n\n') || "";
                 smartExport.startSmartExport(reportTxt, 'notes', notesLanguage);
            }},
            { label: "Dev: Load Stress Test Data", desc: "Populate complex audit data", icon: "Database", action: loadStressTestData },
            { label: "Settings / API Key", desc: "Manage configuration", icon: "Settings", action: () => setShowSettingsModal(true) },
        ];
        if (allStandards[standardKey]) {
            const flatten = (list: Clause[]): any[] => list.flatMap(c => {
                const item = { label: `${c.code} ${c.title}`, desc: c.description, type: 'clause', icon: 'Book', action: () => insertTextAtCursor(`[${c.code}] ${c.title}`) };
                return c.subClauses ? [item, ...flatten(c.subClauses)] : [item];
            });
            return [...actions, ...allStandards[standardKey].groups.flatMap(g => flatten(g.clauses))];
        }
        return actions;
    }, [isDarkMode, standardKey, allStandards, analysisResult, selectedFindings]);

    const getAnalyzeTooltip = () => {
        if (isAnalyzeLoading) return "AI is analyzing...";
        const missing = [];
        if (selectedClauses.length === 0) missing.push("Clauses");
        if (!hasEvidence) missing.push("Evidence");
        if (missing.length > 0) return `Feature Unavailable. Missing: ${missing.join(" & ")}.`;
        return "Ready! Click to Start AI Analysis.";
    };

    return (
        <div className="flex flex-col h-[100dvh] w-full bg-gray-50 dark:bg-slate-900 transition-colors duration-500 ease-soft relative">
            {toastMsg && <Toast message={toastMsg} onClose={() => setToastMsg(null)} />}
            {aiError && (
                <div className="fixed top-20 right-5 z-[9999] max-w-sm w-full bg-white dark:bg-slate-800 border-l-4 border-red-500 shadow-2xl rounded-r-xl p-4 animate-in slide-in-from-right-10 flex flex-col gap-2">
                    <div className="flex justify-between items-start"><div className="flex items-center gap-2 text-red-600 dark:text-red-400 font-bold"><Icon name="AlertCircle" size={20}/><span>System Alert</span></div><button onClick={() => setAiError(null)} className="text-gray-400 hover:text-slate-800 dark:hover:text-white"><Icon name="X" size={18}/></button></div>
                    <p className="text-sm text-slate-600 dark:text-slate-300 leading-relaxed">{aiError}</p>
                </div>
            )}
            {/* HEADER */}
            <div className="flex-shrink-0 px-4 md:px-6 py-0 border-b border-gray-200 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-[70] relative flex justify-between items-center h-16">
                <div className="flex items-center h-full gap-3 md:gap-5">
                    <div className={`relative group cursor-pointer flex items-center justify-center`} onClick={() => { setIsSidebarOpen(!isSidebarOpen); setLogoKey(prev => prev + 1); }}>
                        <div className="relative w-10 h-10 md:w-14 md:h-14 flex items-center justify-center">
                            <div className="absolute -inset-4 bg-indigo-500/0 rounded-full blur-xl group-hover:bg-indigo-500/10 transition-all"></div>
                            <div className="absolute -inset-1 rounded-full bg-[conic-gradient(from_0deg,transparent_0_deg,#f472b6_100deg,#8b5cf6_200deg,#06b6d4_300deg,transparent_360deg)] opacity-30 blur-lg animate-[spin_4s_linear_infinite] group-hover:opacity-70 group-hover:blur-md transition-all"></div>
                            <div className="relative z-10">{isSidebarOpen ? <div className="relative w-8 h-8"><div className="absolute inset-0 border-2 border-transparent border-t-indigo-500 border-b-cyan-500 rounded-full animate-infinity-spin"></div><div className="absolute inset-2 border-2 border-transparent border-l-purple-500 border-r-pink-500 rounded-full animate-spin-reverse"></div></div> : <div className="hover:scale-110 transition-transform"><Icon name="TDLogo" size={32} /></div>}</div>
                        </div>
                    </div>
                    <div className="flex items-center gap-2 md:gap-3">
                        <h1 className="hidden md:block text-lg font-bold tracking-tight text-slate-900 dark:text-white leading-none">ISO Audit <span className="font-light text-slate-400">Pro</span></h1>
                        <div className="hidden md:block h-5 w-px bg-gray-200 dark:bg-slate-700 mx-1"></div>
                        <div className="flex items-center"><span className="text-[11px] font-bold text-indigo-600 dark:text-indigo-300 bg-indigo-50 dark:bg-indigo-900/30 px-3 py-1 rounded-full border border-indigo-100 dark:border-indigo-800/50 uppercase tracking-wider">{allStandards[standardKey]?.name.split(' ')[1] || 'ISO'}</span></div>
                    </div>
                </div>
                <div className="flex items-center gap-2">
                    <button onClick={() => setIsCmdPaletteOpen(true)} className="p-2 rounded-lg text-slate-500 hover:text-indigo-600 dark:text-slate-400 dark:hover:text-indigo-400 hover:bg-gray-100 dark:hover:bg-slate-800 transition-all"><Icon name="Search" size={20}/></button>
                    <div className="hidden lg:block"><FontSizeController fontSizeScale={fontSizeScale} adjustFontSize={(dir: any) => setFontSizeScale(prev => dir === 'increase' ? Math.min(prev + 0.1, 1.3) : Math.max(prev - 0.1, 0.8))} /></div>
                    <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-2 rounded-lg text-slate-500 hover:text-slate-900 dark:text-slate-400 dark:hover:text-white hover:bg-gray-100 dark:hover:bg-slate-800 transition-all"><Icon name={isDarkMode ? "Sun" : "Moon"} size={18}/></button>
                    <div className="hidden md:block h-4 w-px bg-gray-200 dark:bg-slate-800 mx-1"></div>
                    <button onClick={() => setShowSettingsModal(true)} className="group relative w-8 h-8 flex items-center justify-center transition-all"><div className={`absolute inset-0 rounded-full opacity-20 animate-ping ${gemini.activeKeyId ? 'bg-emerald-500' : 'bg-red-500'}`}></div><div className={`relative w-2.5 h-2.5 rounded-full ring-2 ring-white dark:ring-slate-900 ${gemini.activeKeyId ? 'bg-emerald-500' : 'bg-red-500'}`}></div></button>
                    <button onClick={() => setShowAboutModal(true)} className="ml-1 p-2 text-slate-400 hover:text-indigo-600 transition-colors"><Icon name="Info" size={18}/></button>
                </div>
            </div>

            <div className="flex-1 flex overflow-hidden relative">
                <div className={`${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} fixed top-16 bottom-0 left-0 z-[60] md:absolute md:inset-y-0 md:relative md:top-0 md:translate-x-0 transition-transform duration-500 ease-fluid-spring h-[calc(100%-4rem)] md:h-full`}>
                    <Sidebar isOpen={isSidebarOpen} width={sidebarWidth} setWidth={setSidebarWidth} standards={allStandards} standardKey={standardKey} setStandardKey={setStandardKey} auditInfo={auditInfo} setAuditInfo={setAuditInfo} selectedClauses={selectedClauses} setSelectedClauses={setSelectedClauses} onAddNewStandard={() => { const name = prompt("Enter new Standard Name:"); if(name) setCustomStandards(prev => ({...prev, [name]: { name, description: "Custom", groups: [] }})); }} onUpdateStandard={handleUpdateStandard} onResetStandard={handleResetStandard}/>
