                {isSidebarOpen && <div className="fixed top-16 bottom-0 inset-x-0 bg-black/50 z-50 md:hidden backdrop-blur-sm" onClick={() => setIsSidebarOpen(false)}/>}

                <div className={`flex-1 flex flex-col min-w-0 transition-all duration-500 relative w-full ${isDragging ? 'ring-4 ring-indigo-500/50 scale-[0.99]' : ''} ${currentTabConfig.bgSoft} border-t-4 ${currentTabConfig.borderClass}`} onDragOver={handleDragOver} onDragLeave={() => setIsDragging(false)} onDrop={handleDrop}>
                    {isDragging && <div className="absolute inset-0 z-50 flex items-center justify-center bg-indigo-500/10 backdrop-blur-sm m-4 pointer-events-none rounded-3xl border-4 border-dashed border-indigo-500"><div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-2xl flex flex-col items-center animate-bounce"><Icon name="UploadCloud" size={48} className="text-indigo-500 mb-4"/><h3 className="text-2xl font-black text-indigo-600">Drop Evidence</h3></div></div>}

