                            <div ref={tabsContainerRef} className="relative flex justify-between bg-gray-100 dark:bg-slate-800 p-1 rounded-xl w-full">
                                <div className={`absolute top-1 bottom-1 shadow-sm rounded-lg transition-all duration-500 ease-fluid-spring z-0 ${tabStyle.color}`} style={{ left: tabStyle.left, width: tabStyle.width, opacity: tabStyle.opacity }}/>
                                {tabsList.map((tab, idx) => (<button key={tab.id} ref={el => { tabsRef.current[idx] = el; }} onClick={() => setLayoutMode(tab.id as LayoutMode)} className={`flex-1 relative z-10 flex items-center justify-center gap-2 px-1 md:px-4 py-2 rounded-lg text-xs md:text-sm font-bold transition-colors ${layoutMode === tab.id ? 'text-white' : 'text-slate-500'}`}><Icon name={tab.icon} size={16}/><span className={`${isSidebarOpen ? 'hidden xl:inline' : 'hidden md:inline'}`}>{tab.label}</span></button>))}
                            </div>
                        </div>
                        <div className="flex gap-2 items-center flex-shrink-0 pl-2 border-l border-gray-200 dark:border-slate-800">
                            <button onClick={handleRecall} className="p-3 bg-gray-100 dark:bg-slate-800 hover:bg-gray-200 text-slate-600 dark:text-slate-300 rounded-xl transition-all hover:scale-105"><Icon name="History" size={18}/></button>
                            <button onClick={handleNewSession} className="p-3 bg-gray-100 dark:bg-slate-800 hover:bg-gray-200 text-slate-600 dark:text-slate-300 rounded-xl transition-all hover:text-indigo-600 hover:scale-105"><Icon name="Session4_FilePlus" size={18}/></button>
                        </div>
                    </div>

                    <div className="flex-1 overflow-hidden relative p-4 md:p-6">
                        {layoutMode === 'evidence' && (
                            <div className="h-full flex flex-col gap-4 animate-fade-in-up relative">
                                <div className="flex-1 flex flex-col gap-4 min-h-0">
                                    <div className="flex-1 bg-white dark:bg-slate-900 rounded-3xl shadow-sm border border-gray-100 dark:border-slate-800 overflow-hidden flex flex-col relative group focus-within:ring-2 ring-indigo-500/20">
                                        <textarea ref={evidenceTextareaRef} className="flex-1 w-full h-full p-6 bg-transparent resize-none focus:outline-none text-slate-700 dark:text-slate-300 font-mono text-sm leading-relaxed" placeholder="Paste audit evidence here..." value={evidence} onChange={(e) => setEvidence(e.target.value)} onPaste={handlePaste}/>
                                        <div className="absolute bottom-4 right-4 flex gap-2">
                                            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" multiple onChange={(e) => e.target.files && setPastedImages(prev => [...prev, ...Array.from(e.target.files!)])} />
                                            <button onClick={() => fileInputRef.current?.click()} className="p-3 rounded-xl bg-gray-100 dark:bg-slate-800 hover:bg-indigo-50 text-slate-600 hover:text-indigo-600 transition-all hover:scale-110"><Icon name="Demo8_GridPlus" size={20}/></button>
                                        </div>
                                    </div>
                                    {pastedImages.length > 0 && <div className="flex-shrink-0 p-3 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-2xl animate-in slide-in-from-bottom-5">
                                        <div className="flex justify-between items-center mb-2 px-1"><h4 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Pending Extraction ({pastedImages.length})</h4><button onClick={() => setPastedImages([])} className="text-xs text-red-500 font-bold">Clear All</button></div>
                                        <div className="flex gap-3 overflow-x-auto custom-scrollbar pb-2">
                                            {pastedImages.map((file, idx) => (<div key={idx} className="relative group flex-shrink-0 w-24 h-24 bg-white dark:bg-slate-800 rounded-xl overflow-hidden"><img src={URL.createObjectURL(file)} className="w-full h-full object-cover"/><div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center"><button onClick={() => setPastedImages(prev => prev.filter((_, i) => i !== idx))} className="bg-red-500 text-white rounded-full p-1"><Icon name="X" size={14}/></button></div></div>))}
                                            <div className="flex-shrink-0 w-24 h-24 flex items-center justify-center"><button onClick={handleOcrUpload} disabled={isOcrLoading} className="w-full h-full bg-indigo-600 text-white rounded-xl flex flex-col items-center justify-center gap-2 hover:scale-105 transition-all">{isOcrLoading ? <Icon name="Loader" className="animate-spin" size={24}/> : <Icon name="ScanText" size={24}/>}<span className="text-[10px] font-bold">Extract</span></button></div>
                                        </div>
                                    </div>}
                                </div>
                                <div className="flex items-center justify-center md:justify-end gap-2 w-full">
                                    <button onClick={handleAnalyze} disabled={!isReadyForAnalysis} title={getAnalyzeTooltip()} className={`h-10 px-4 rounded-xl font-bold flex items-center gap-3 ${isReadyForAnalysis ? "btn-shrimp shadow-xl active:scale-95" : "bg-gray-200 dark:bg-slate-800 opacity-70 cursor-not-allowed"}`}>{isAnalyzeLoading ? <SparkleLoader className="text-white"/> : <Icon name="Wand2" size={18}/>}<span className="hidden md:inline text-xs uppercase tracking-wider">Analyze Compliance</span></button>
                                    <button onClick={() => smartExport.startSmartExport(evidence, 'evidence', evidenceLanguage)} className="h-10 px-4 bg-white dark:bg-slate-800 border hover:border-indigo-500 rounded-xl text-xs font-bold flex items-center gap-2 transition-all"><Icon name="Download"/> <span className="hidden md:inline">Export Raw</span><div className="lang-pill-container ml-1"><span onClick={(e) => {e.stopPropagation(); setEvidenceLanguage('en');}} className={`lang-pill-btn ${evidenceLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span><span onClick={(e) => {e.stopPropagation(); setEvidenceLanguage('vi');}} className={`lang-pill-btn ${evidenceLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span></div></button>
                                </div>
                            </div>
                        )}

                        {layoutMode === 'findings' && (
                             <div className="h-full flex flex-col animate-fade-in-up">
                                <div ref={findingsContainerRef} className="flex-1 overflow-y-auto custom-scrollbar space-y-4 pr-2 pb-4">
                                    {(!analysisResult || analysisResult.length === 0) && !isAnalyzeLoading && <div className="h-full flex flex-col items-center justify-center text-slate-400 opacity-60"><Icon name="Wand2" size={64} className="mb-4"/><p>No analysis data yet.</p></div>}
                                    {findingsViewMode === 'matrix' && analysisResult && <div className="grid grid-cols-4 sm:grid-cols-6 md:grid-cols-10 gap-2 p-1">{analysisResult.map((result, idx) => { const isActive = selectedFindings[result.clauseId]; let bgColor = isActive ? (result.status === 'COMPLIANT' ? 'bg-emerald-500' : result.status === 'NC_MAJOR' ? 'bg-red-600' : result.status === 'NC_MINOR' ? 'bg-orange-500' : 'bg-blue-500') : 'bg-gray-200 dark:bg-slate-700'; return (<div key={result.clauseId} className={`aspect-square rounded-lg flex items-center justify-center text-[10px] font-bold cursor-pointer hover:scale-110 shadow-sm ${bgColor} ${isActive ? 'text-white' : 'text-slate-500 opacity-50'}`} onClick={() => setSelectedFindings(prev => ({...prev, [result.clauseId]: !prev[result.clauseId]}))}>{result.clauseId}</div>); })}</div>}
                                    {findingsViewMode === 'list' && analysisResult?.map((result, idx) => (
                                        <div key={result.clauseId} className={`p-5 rounded-2xl bg-white dark:bg-slate-900 border-l-4 shadow-sm transition-all ${!selectedFindings[result.clauseId] ? 'opacity-60 grayscale' : result.status === 'COMPLIANT' ? 'border-emerald-500' : result.status === 'NC_MAJOR' ? 'border-red-600' : result.status === 'NC_MINOR' ? 'border-orange-500' : 'border-blue-500'}`}>
                                            <div className="flex justify-between items-start gap-4">
                                                <div className="flex-1">
                                                    <div className="flex items-center gap-3 mb-2"><input type="checkbox" checked={!!selectedFindings[result.clauseId]} onChange={() => setSelectedFindings(prev => ({...prev, [result.clauseId]: !prev[result.clauseId]}))} className="w-5 h-5 rounded text-indigo-600"/><span className="font-black text-sm bg-gray-100 dark:bg-slate-800 px-2 py-0.5 rounded">{result.clauseId}</span><select value={result.status} onChange={(e) => handleUpdateFinding(idx, 'status', e.target.value as FindingStatus)} className={`text-xs font-bold px-2 py-0.5 rounded uppercase border-none outline-none cursor-pointer ${result.status === 'COMPLIANT' ? 'bg-emerald-100 text-emerald-700' : result.status === 'NC_MAJOR' ? 'bg-red-100 text-red-700' : result.status === 'NC_MINOR' ? 'bg-orange-100 text-orange-800' : 'bg-blue-100 text-blue-700'}`}><option value="COMPLIANT">COMPLIANT</option><option value="OFI">OFI</option><option value="NC_MINOR">NC MINOR</option><option value="NC_MAJOR">NC MAJOR</option></select></div>
                                                    <input className="w-full text-sm font-bold mb-1 bg-transparent border-b border-transparent hover:border-gray-200 focus:border-indigo-500 outline-none" value={result.reason} onChange={(e) => handleUpdateFinding(idx, 'reason', e.target.value)}/>
                                                    <div className="bg-gray-50 dark:bg-slate-950/50 p-2 rounded-lg border border-gray-100 mt-1"><textarea className="w-full text-xs text-slate-500 italic bg-transparent border-none resize-y min-h-[40px]" value={result.evidence} onChange={(e) => handleUpdateFinding(idx, 'evidence', e.target.value)}/></div>
                                                    {result.suggestion && <div className="mt-2 flex gap-2"><Icon name="Lightbulb" size={14} className="text-amber-500"/><p className="text-xs text-slate-600">{result.suggestion}</p></div>}
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                    {isAnalyzeLoading && <div className="p-5 rounded-2xl bg-white dark:bg-slate-900 border border-indigo-100 shadow-lg animate-pulse"><div className="flex items-center gap-3"><Icon name="Loader" size={20} className="animate-spin text-indigo-600"/><p className="text-sm font-bold">{loadingMessage}</p></div></div>}
                                </div>
                                <div className="flex items-center justify-center md:justify-end gap-2 w-full mt-2">
                                    <div className="h-10 bg-gray-100 dark:bg-slate-800 p-1 rounded-xl flex items-center"><button onClick={() => setFindingsViewMode('list')} className={`h-full px-3 rounded-lg flex items-center gap-2 text-xs font-bold ${findingsViewMode === 'list' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}><Icon name="LayoutList" size={16}/> List</button><button onClick={() => setFindingsViewMode('matrix')} className={`h-full px-3 rounded-lg flex items-center gap-2 text-xs font-bold ${findingsViewMode === 'matrix' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}><Icon name="Grid" size={16}/> Matrix</button></div>
                                    <button onClick={() => { const reportTxt = analysisResult?.filter(r => selectedFindings[r.clauseId]).map(r => `[${r.status}] Clause ${r.clauseId}: ${r.conclusion_report}`).join('\n\n') || ""; smartExport.startSmartExport(reportTxt, 'notes', notesLanguage); }} disabled={!analysisResult || analysisResult.length === 0} className="h-10 px-4 bg-white dark:bg-slate-800 border hover:border-indigo-500 rounded-xl text-xs font-bold flex items-center gap-2"><Icon name="Download"/> Download Findings <div className="lang-pill-container ml-2"><span onClick={(e) => {e.stopPropagation(); setNotesLanguage('en');}} className={`lang-pill-btn ${notesLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span><span onClick={(e) => {e.stopPropagation(); setNotesLanguage('vi');}} className={`lang-pill-btn ${notesLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span></div></button>
                                </div>
