                                    {!finalReportText ? <div className="flex-1 flex flex-col items-center justify-center text-center p-8"><Icon name="FileText" size={40} className="text-indigo-200 mb-6"/><h4 className="text-lg font-bold">Ready to Synthesize</h4><p className="text-sm text-slate-500 max-w-md">Generate comprehensive report.</p></div> : <textarea className="flex-1 w-full h-full bg-transparent resize-none focus:outline-none text-slate-800 dark:text-slate-200 font-mono text-sm leading-relaxed" value={finalReportText} onChange={(e) => setFinalReportText(e.target.value)}/>}
                                </div>
                                <div className="flex items-center justify-center md:justify-end gap-2 w-full mt-2">
                                    <div className="relative"><input type="file" id="template-upload" className="hidden" accept=".txt,.md,.docx" onChange={handleTemplateUpload}/><label htmlFor="template-upload" className={`cursor-pointer h-10 px-4 rounded-xl text-xs font-bold flex items-center gap-2 border shadow-sm ${reportTemplate ? 'bg-indigo-50 text-indigo-600 border-indigo-200' : 'bg-gray-100 text-slate-600'}`}><Icon name="UploadCloud" size={14}/> {templateFileName ? "Change Template" : "Upload Template"}</label></div>
                                    <button onClick={handleGenerateReport} disabled={!analysisResult || analysisResult.length === 0} className="h-10 px-4 bg-gradient-to-r from-indigo-600 to-purple-600 text-white rounded-xl font-bold text-xs shadow-xl flex items-center gap-3">{isReportLoading ? <SparkleLoader className="text-white"/> : <Icon name="Wand2" size={18}/>} Generate Final Report</button>
                                    <button onClick={() => smartExport.startSmartExport(finalReportText || "", 'report', exportLanguage)} disabled={!finalReportText} className="h-10 px-4 bg-white dark:bg-slate-800 border hover:border-indigo-500 rounded-xl text-xs font-bold flex items-center gap-2"><Icon name="Download"/> Export <div className="lang-pill-container ml-2"><span onClick={(e) => {e.stopPropagation(); setExportLanguage('en');}} className={`lang-pill-btn ${exportLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span><span onClick={(e) => {e.stopPropagation(); setExportLanguage('vi');}} className={`lang-pill-btn ${exportLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span></div></button>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* MODALS */}
            <CommandPaletteModal isOpen={isCmdPaletteOpen} onClose={() => setIsCmdPaletteOpen(false)} actions={commandActions} onSelectAction={(item: any) => { item.action(); setIsCmdPaletteOpen(false); }}/>
            <ReleaseNotesModal isOpen={showAboutModal} onClose={() => setShowAboutModal(false)} />

            <Modal isOpen={showSettingsModal} title="Settings & API Keys" onClose={() => setShowSettingsModal(false)}>
                <div className="space-y-6">
                    <div>
                        <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-3">Manage API Keys</h4>
                        <div className="space-y-3">
                            {gemini.apiKeys.map(profile => (
                                <div key={profile.id} className={`p-3 rounded-xl border flex items-center justify-between ${profile.id === gemini.activeKeyId ? 'bg-indigo-50 border-indigo-200' : 'bg-white border-gray-100 dark:bg-slate-800 dark:border-slate-700'}`}>
                                    <div className="flex items-center gap-3 overflow-hidden"><div onClick={() => gemini.setActiveKeyId(profile.id)} className={`cursor-pointer w-4 h-4 rounded-full border-2 flex items-center justify-center ${profile.id === gemini.activeKeyId ? 'border-indigo-500' : 'border-gray-300'}`}>{profile.id === gemini.activeKeyId && <div className="w-2 h-2 rounded-full bg-indigo-500"></div>}</div><div className="flex flex-col min-w-0"><div className="flex items-center gap-2"><span className="text-sm font-bold truncate">{profile.label}</span>{profile.status === 'valid' && <span className="text-[9px] bg-emerald-100 text-emerald-700 px-1.5 rounded font-bold">Valid</span>}{profile.status === 'invalid' && <span className="text-[9px] bg-red-100 text-red-700 px-1.5 rounded font-bold">Invalid</span>}{profile.status === 'quota_exceeded' && <span className="text-[9px] bg-orange-100 text-orange-700 px-1.5 rounded font-bold">Quota</span>}{profile.status === 'checking' && <Icon name="Loader" size={10} className="animate-spin text-indigo-500"/>}</div><div className="flex items-center gap-2"><span className="text-[10px] text-slate-400 font-mono truncate">{profile.key.substring(0, 8)}...</span>{profile.activeModel && <span className="text-[9px] font-mono bg-blue-50 text-blue-600 px-1.5 rounded">{profile.activeModel.replace('gemini-', '')}</span>}</div></div></div>
                                    <div className="flex items-center gap-1"><button onClick={() => gemini.handleRefreshStatus(profile.id)} className="p-2 text-slate-400 hover:text-indigo-500"><Icon name="RefreshCw" size={14} className={profile.status === 'checking' ? 'animate-spin' : ''}/></button><button onClick={() => gemini.handleDeleteKey(profile.id)} className="p-2 text-slate-400 hover:text-red-500"><Icon name="Trash2" size={14}/></button></div>
                                </div>
                            ))}
                            <div className="p-3 bg-gray-50 dark:bg-slate-800/50 rounded-xl border border-dashed border-gray-300 flex flex-col gap-3">
                                <input className="w-full bg-transparent text-xs outline-none border-b border-gray-200 pb-2" placeholder="Enter API Key" value={newKeyInput} onChange={(e) => setNewKeyInput(e.target.value)}/>
                                <div className="flex gap-2"><input className="flex-1 bg-transparent text-xs outline-none border-b border-gray-200 pb-2" placeholder="Label" value={newKeyLabel} onChange={(e) => setNewKeyLabel(e.target.value)}/><button onClick={() => { gemini.handleAddKey(newKeyInput, newKeyLabel); setNewKeyInput(""); setNewKeyLabel(""); }} disabled={!newKeyInput || gemini.isCheckingKey} className="px-4 py-1.5 bg-indigo-600 text-white text-xs font-bold rounded-lg">{gemini.isCheckingKey ? <Icon name="Loader" className="animate-spin"/> : "Add"}</button></div>
                            </div>
                        </div>
                    </div>
                </div>
            </Modal>

            {smartExport.exportState.isOpen && (
                <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
                    <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-3xl shadow-2xl border border-gray-100 dark:border-slate-800 p-6">
                        <div className="flex justify-between items-start mb-4"><div><h3 className="text-lg font-black flex items-center gap-2"><Icon name="Download" className="text-indigo-500"/> Export Manager</h3><p className="text-xs text-slate-500">Refining to {smartExport.exportState.targetLang === 'vi' ? 'Vietnamese' : 'English'}</p></div>{!smartExport.exportState.isPaused && !smartExport.exportState.isFinished && <span className="text-xs font-mono bg-indigo-100 text-indigo-600 px-2 py-1 rounded animate-pulse">Processing...</span>}</div>
                        <div className="mb-2 flex justify-between text-xs font-bold"><span>Progress</span><span>{Math.round((smartExport.exportState.processedChunksCount / smartExport.exportState.totalChunks) * 100)}%</span></div>
                        <div className="w-full h-3 bg-gray-100 dark:bg-slate-800 rounded-full overflow-hidden mb-6 relative"><div className={`h-full transition-all duration-500 ease-out ${smartExport.exportState.error ? 'bg-red-500' : smartExport.exportState.isFinished ? 'bg-emerald-500' : 'bg-indigo-500'}`} style={{ width: `${(smartExport.exportState.processedChunksCount / smartExport.exportState.totalChunks) * 100}%` }}><div className="absolute inset-0 bg-white/20 animate-[shimmer_2s_infinite]"></div></div></div>
                        <div className="bg-gray-50 dark:bg-slate-950/50 p-4 rounded-xl mb-6 min-h-[100px] flex flex-col justify-center items-center text-center">
                            {smartExport.exportState.isFinished ? <div className="text-emerald-500 flex flex-col items-center gap-2"><Icon name="CheckCircle2" size={32}/><span className="font-bold">Export Complete!</span><span className="text-xs text-slate-500">Downloading...</span></div> : smartExport.exportState.error ? <div className="text-red-500 flex flex-col items-center gap-2 w-full"><Icon name="AlertCircle" size={32}/><span className="font-bold">Export Paused</span><span className="text-xs text-slate-500 mb-2">{smartExport.exportState.error}</span><div className="w-full mt-2"><input type="text" className="w-full bg-white dark:bg-slate-900 border border-red-200 rounded-lg px-3 py-2 text-xs" placeholder="Paste Rescue Key..." value={smartExport.rescueKey} onChange={(e) => smartExport.setRescueKey(e.target.value)}/></div></div> : <div className="flex flex-col items-center gap-2"><p className="text-xs text-slate-500">Processing Chunk</p><p className="text-2xl font-black text-indigo-600">{smartExport.exportState.processedChunksCount + 1} <span className="text-base text-slate-400 font-normal">/ {smartExport.exportState.totalChunks}</span></p></div>}
                        </div>
                        <div className="flex gap-3">{smartExport.exportState.isPaused ? <><button onClick={() => setShowSettingsModal(true)} className="flex-1 py-3 bg-gray-100 hover:bg-gray-200 rounded-xl font-bold text-xs">Manage Keys</button><button onClick={smartExport.handleResumeExport} disabled={smartExport.isRescuing} className={`flex-1 py-3 text-white rounded-xl font-bold text-xs shadow-lg flex items-center justify-center gap-2 ${smartExport.rescueKey ? 'bg-emerald-500 hover:bg-emerald-600' : 'bg-indigo-600 hover:bg-indigo-700'}`}>{smartExport.isRescuing ? <Icon name="Loader" className="animate-spin" size={14}/> : null}{smartExport.rescueKey ? "Add Key & Resume" : "Resume Export"}</button></> : <button onClick={() => smartExport.setExportState(prev => ({ ...prev, isOpen: false, isPaused: true }))} className="w-full py-3 bg-gray-100 hover:bg-gray-200 text-slate-500 rounded-xl font-bold text-xs">{smartExport.exportState.isFinished ? "Close" : "Cancel"}</button>}</div>
                    </div>
                </div>
            )}
            {isReportLoading && <AINeuralLoader message="Synthesizing Audit Report..." />}
        </div>
    );
}

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Icon, IconSelect, IconInput, Modal } from './UI';
import { StandardsData, AuditInfo, Clause, Group, Standard } from '../types';
import { useDebounce, copyToClipboard, cleanAndParseJSON } from '../utils';
import { AUDIT_TYPES, STANDARDS_DATA } from '../constants';
import { generateMissingDescriptions } from '../services/geminiService';

interface SidebarProps {
    isOpen: boolean;
    width: number;
    setWidth: (w: number) => void;
    standards: StandardsData;
    standardKey: string;
    setStandardKey: (k: string) => void;
    auditInfo: AuditInfo;
    setAuditInfo: (info: AuditInfo) => void;
    selectedClauses: string[];
    setSelectedClauses: React.Dispatch<React.SetStateAction<string[]>>;
    onAddNewStandard: () => void;
    onUpdateStandard: (std: Standard) => void;
    onResetStandard: (key: string) => void;
}

const Sidebar = ({ isOpen, width, setWidth, standards, standardKey, setStandardKey, auditInfo, setAuditInfo, selectedClauses, setSelectedClauses, onAddNewStandard, onUpdateStandard, onResetStandard }: SidebarProps) => {
    const sidebarRef = useRef<HTMLDivElement>(null);
    const scrollContainerRef = useRef<HTMLDivElement>(null); 
    const [isResizing, setIsResizing] = useState(false);
    const [searchQueryRaw, setSearchQueryRaw] = useState("");
    const [expandedGroups, setExpandedGroups] = useState<string[]>([]);
    const [expandedClauses, setExpandedClauses] = useState<string[]>([]);
    const [showIntegrityModal, setShowIntegrityModal] = useState(false);

    // UI State: Collapse Audit Info to save space
    const [isInfoExpanded, setIsInfoExpanded] = useState(false);

    // UI State: Scroll-aware Header Visibility
    const [isHeaderVisible, setIsHeaderVisible] = useState(true);

    // Auto-repair states
    const [isRepairing, setIsRepairing] = useState(false);
    const [copiedClauseId, setCopiedClauseId] = useState<string | null>(null);
    const [repairStats, setRepairStats] = useState<{ fixed: number, cleaned: number } | null>(null);
    const [repairedIds, setRepairedIds] = useState<string[]>([]);

    const searchQuery = useDebounce(searchQueryRaw, 300);

    const startResizing = (e: React.MouseEvent) => {
        if ((e.target as Element).classList.contains('resize-handle')) {
            e.preventDefault();
            setIsResizing(true);
            document.body.style.cursor = 'col-resize';
            document.body.style.userSelect = 'none'; 
        }
    };

    useEffect(() => {
        const stopResizing = () => {
            if (isResizing) {
                setIsResizing(false);
                document.body.style.cursor = '';
                document.body.style.userSelect = '';

                if (sidebarRef.current) {
                    const finalWidth = parseInt(sidebarRef.current.style.width, 10);
                    if (!isNaN(finalWidth)) {
                        setWidth(finalWidth);
                    }
                }
            }
        };

        const resize = (e: MouseEvent) => {
            if (isResizing && sidebarRef.current) {
                const MIN_SIDEBAR_WIDTH = 300; // Lower min width for flexibility
                const MAX_SIDEBAR_LIMIT = 800;
                const newWidth = Math.max(MIN_SIDEBAR_WIDTH, Math.min(e.clientX, MAX_SIDEBAR_LIMIT));
                sidebarRef.current.style.width = `${newWidth}px`;
            }
        };

        if (isResizing) {
            window.addEventListener('mousemove', resize);
            window.addEventListener('mouseup', stopResizing);
        }
        return () => {
            window.removeEventListener('mousemove', resize);
            window.removeEventListener('mouseup', stopResizing);
        };
    }, [isResizing, setWidth]);

    // --- AGGRESSIVE SCROLL LOGIC ---
    const handleScroll = (e: React.UIEvent<HTMLDivElement>) => {
        if (isResizing) return;

        const target = e.currentTarget;
        const scrollTop = target.scrollTop;
        const SCROLL_THRESHOLD = 50; 

        if (scrollTop > SCROLL_THRESHOLD && isHeaderVisible) {
            setIsHeaderVisible(false);
        } else if (scrollTop <= SCROLL_THRESHOLD && !isHeaderVisible) {
            setIsHeaderVisible(true);
        }
    };

    useEffect(() => {
        if (scrollContainerRef.current) scrollContainerRef.current.scrollTop = 0;
    }, [standardKey]);

    // --- HEALTH CHECK LOGIC ---
    const runHealthCheck = () => {
        if (!standardKey || !standards[standardKey]) return { isHealthy: false, score: 0, integrity: [], completeness: [] };
        const data = standards[standardKey];
        const integrity: { label: string, status: 'pass' | 'fail', detail: string }[] = [];
        const completeness: { label: string, status: 'pass' | 'fail', detail: string }[] = [];

        const allClauses = data.groups.flatMap(g => g.clauses);
        const flatten = (list: Clause[]): Clause[] => {
            return list.reduce((acc, c) => {
                acc.push(c);
                if (c.subClauses) acc.push(...flatten(c.subClauses));
                return acc;
            }, [] as Clause[]);
        };
        const flatList = flatten(allClauses);

        const missingDesc = flatList.filter(c => !c.description || c.description.trim().length < 2).length;
        integrity.push({ 
            label: 'Content Quality', 
            status: missingDesc === 0 ? 'pass' : 'fail', 
            detail: missingDesc === 0 ? 'Descriptions OK' : `${missingDesc} incomplete` 
        });

        const uniqueCodes = new Set(flatList.map(c => c.code));
        const duplicateCount = flatList.length - uniqueCodes.size;
        integrity.push({ 
            label: 'Data Cleanliness', 
            status: duplicateCount === 0 ? 'pass' : 'fail', 
            detail: duplicateCount === 0 ? 'Clean' : `${duplicateCount} Duplicates` 
        });

        if (standardKey.includes("9001")) {
            const crucial = ['8.4', '8.6', '8.7', '7.1.4'];
            crucial.forEach(code => {
                const found = flatList.some(c => c.code === code);
                completeness.push({ 
                    label: `Clause ${code}`, 
                    status: found ? 'pass' : 'fail', 
                    detail: found ? 'Present' : 'Missing (Required)' 
                });
            });
        }

        if (standardKey.includes("27001")) {
            const annexItems = flatList.filter(c => c.code.startsWith("A."));
            const isFullSet = annexItems.length >= 90; 
            completeness.push({ 
                label: 'Annex A Controls', 
                status: isFullSet ? 'pass' : 'fail', 
                detail: isFullSet ? `${annexItems.length} Controls (OK)` : `${annexItems.length}/93 (Incomplete)` 
            });
        }

        const integrityPass = integrity.every(i => i.status === 'pass');
        const completenessPass = completeness.every(i => i.status === 'pass');
        const isHealthy = integrityPass && completenessPass;

        const totalItems = integrity.length + completeness.length;
        const passItems = integrity.filter(i => i.status === 'pass').length + completeness.filter(i => i.status === 'pass').length;
        const score = Math.round((passItems / (totalItems || 1)) * 100);

        return { isHealthy, score, integrity, completeness };
    };

    const handleAutoRepair = async () => {
        if (!standardKey || !standards[standardKey]) return;
        setIsRepairing(true);
        setRepairStats(null);
        try {
            const currentStandard = JSON.parse(JSON.stringify(standards[standardKey])) as Standard; 
            const missingClauses: {ref: Clause, code: string, title: string}[] = [];
            const fixedIds: string[] = [];
            let duplicateRemovedCount = 0;

            const findMissing = (list: Clause[]) => {
                list.forEach(c => {
                    if (!c.description || c.description.trim().length < 5) {
                        missingClauses.push({ ref: c, code: c.code, title: c.title });
                    }
                    if (c.subClauses) findMissing(c.subClauses);
                });
            };
            currentStandard.groups.forEach((g: Group) => findMissing(g.clauses));

            if (missingClauses.length > 0) {
                const targets = missingClauses.map(i => ({ code: i.code, title: i.title }));
                const jsonStr = await generateMissingDescriptions(targets);
                const descriptions = cleanAndParseJSON(jsonStr);

                if (Array.isArray(descriptions)) {
                    const descMap = descriptions.reduce((acc: any, item: any) => {
                        if(item.code && item.description) acc[item.code] = item.description;
                        return acc;
                    }, {});

                    missingClauses.forEach(item => {
                        if (descMap[item.code]) {
                            item.ref.description = descMap[item.code];
                            fixedIds.push(item.ref.id);
                        }
                    });
                } else if (descriptions && typeof descriptions === 'object') {
                    missingClauses.forEach(item => {
                        if (descriptions[item.code]) {
                            item.ref.description = descriptions[item.code];
                            fixedIds.push(item.ref.id);
                        }
                    });
                }
            }

            const cleanClauses = (clauses: Clause[]): Clause[] => {
                const seenCodes = new Set<string>();
                const unique: Clause[] = [];
                for (const c of clauses) {
                    if (!seenCodes.has(c.code)) {
                        seenCodes.add(c.code);
                        if (c.subClauses) {
                            c.subClauses = cleanClauses(c.subClauses);
                        }
                        unique.push(c);
                    } else {
                        duplicateRemovedCount++;
                    }
                }
                return unique;
            };

            currentStandard.groups.forEach(g => {
                g.clauses = cleanClauses(g.clauses);
            });

            onUpdateStandard(currentStandard);
            setRepairedIds(fixedIds);
            setRepairStats({ fixed: fixedIds.length, cleaned: duplicateRemovedCount });

        } catch (e) {
            console.error("Repair failed", e);
            alert("Failed to repair automatically.");
        } finally {
            setIsRepairing(false);
        }
    };

    const handleCopySelectedClauses = () => {
        if (!standardKey || !standards[standardKey]) return;
        const findClause = (id: string, list: Clause[]): Clause | undefined => {
            for (let c of list) { 
                if (c.id === id) return c; 
                if (c.subClauses) { 
                    const f = findClause(id, c.subClauses); 
                    if (f) return f; 
                } 
            }
        };
        const allClauses = standards[standardKey].groups.flatMap(g => g.clauses);
        const selectedData = selectedClauses
            .map(id => findClause(id, allClauses))
            .filter((c): c is Clause => !!c)
            .map(c => `[${c.code}] ${c.title}`)
            .join('\n');
        copyToClipboard(selectedData);
    };

    const handleSingleClauseCopy = (e: React.MouseEvent, c: Clause) => {
        e.stopPropagation();
        copyToClipboard(`[${c.code}] ${c.title}`);
        setCopiedClauseId(c.id);
        setTimeout(() => setCopiedClauseId(null), 1500);
    };

    const toggleClauseSelection = (clause: Clause) => {
        const getAllIds = (c: Clause): string[] => {
            let ids = [c.id];
            if (c.subClauses) c.subClauses.forEach(sub => ids.push(...getAllIds(sub)));
            return ids;
        };
        const targetIds = getAllIds(clause);
        const allSelected = targetIds.every(id => selectedClauses.includes(id));
        setSelectedClauses(prev => allSelected ? prev.filter(id => !targetIds.includes(id)) : Array.from(new Set([...prev, ...targetIds])));
    };

    const toggleGroupSelection = (group: Group) => {
        const getAllIds = (list: Clause[]): string[] => {
            let ids: string[] = [];
            list.forEach(c => {
                ids.push(c.id);
                if (c.subClauses) ids.push(...getAllIds(c.subClauses));
            });
            return ids;
        };
        const groupIds = getAllIds(group.clauses);
        const allSelected = groupIds.every(id => selectedClauses.includes(id));

        if (allSelected) {
            setSelectedClauses(prev => prev.filter(id => !groupIds.includes(id)));
        } else {
            setSelectedClauses(prev => [...new Set([...prev, ...groupIds])]);
        }
    };

    const allGroupIds = standards[standardKey]?.groups.map(g => g.id) || [];
    const areAllGroupsExpanded = allGroupIds.length > 0 && expandedGroups.length === allGroupIds.length;

    const toggleExpandAll = () => {
        if (areAllGroupsExpanded) {
            setExpandedGroups([]);
        } else {
            setExpandedGroups(allGroupIds);
        }
    };

    const toggleGroupExpand = (id: string) => setExpandedGroups(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
    const toggleClauseExpand = (id: string) => setExpandedClauses(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);

    const renderClauseItem = (c: Clause, level: number = 0) => {
        const hasSubs = c.subClauses && c.subClauses.length > 0;
        const isExpanded = expandedClauses.includes(c.id) || !!searchQuery;
        const isSelected = selectedClauses.includes(c.id);
        const getChildSelectionStatus = (item: Clause): { all: boolean, some: boolean } => {
            if (!item.subClauses) return { all: selectedClauses.includes(item.id), some: selectedClauses.includes(item.id) };
            const subRes = item.subClauses.map(getChildSelectionStatus);
            const all = selectedClauses.includes(item.id) && subRes.every(r => r.all);
            const some = selectedClauses.includes(item.id) || subRes.some(r => r.some);
            return { all, some };
        };
        const selection = getChildSelectionStatus(c);
        const isCopied = copiedClauseId === c.id;
        const isRepaired = repairedIds.includes(c.id);

        return (
            <div key={c.id} className={`flex flex-col transition-all duration-300 ${level > 0 ? 'ml-4 border-l-2 dark:border-slate-800' : ''}`}>
                <div className={`group flex items-start gap-3 p-2 rounded-xl transition-all duration-200 cursor-pointer ${isSelected ? 'bg-indigo-50/80 dark:bg-indigo-900/20 translate-x-1' : isRepaired ? 'bg-emerald-50/80 dark:bg-emerald-900/20 ring-1 ring-emerald-500/30' : 'hover:bg-gray-100/50 dark:hover:bg-slate-800/50 hover:translate-x-1'}`}>
                    <button onClick={(e) => { e.stopPropagation(); toggleClauseSelection(c); }} className={`mt-1 flex-shrink-0 transition-colors duration-200 ${selection.some ? 'text-indigo-600 dark:text-indigo-400 scale-110' : 'text-gray-300 dark:text-slate-600 hover:text-gray-400'}`}>
                        {selection.all ? <Icon name="CheckSquare" size={16}/> : selection.some ? <div className="w-4 h-4 bg-indigo-500 rounded flex items-center justify-center"><div className="w-2.5 h-0.5 bg-white"></div></div> : <Icon name="Square" size={16}/>}
                    </button>
                    <div 
                        className="flex-1 min-w-0" 
                        onClick={() => hasSubs ? toggleClauseExpand(c.id) : toggleClauseSelection(c)}
                    >
                        <div className="flex items-start justify-between gap-1.5">
                            <div className="flex items-center gap-1.5 flex-wrap">
                                <span className="text-xs font-bold text-indigo-700 dark:text-indigo-400 uppercase shrink-0 bg-indigo-50 dark:bg-indigo-900/30 px-1 rounded">{c.code}</span>
                                <span className="text-sm text-slate-900 dark:text-slate-100 font-medium tracking-tight leading-tight group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors">{c.title}</span>
                                {isRepaired && <span className="text-[9px] font-black bg-emerald-100 text-emerald-600 px-1.5 py-0.5 rounded-md animate-pulse">UPDATED</span>}
                            </div>
                            <div className="flex items-center gap-2">
                                <button
                                    onClick={(e) => handleSingleClauseCopy(e, c)}
                                    className={`p-1 transition-all transform duration-300 ${isCopied ? 'text-emerald-600 scale-125 opacity-100' : 'opacity-0 group-hover:opacity-100 text-gray-300 hover:text-indigo-600 dark:hover:text-indigo-400 hover:scale-110'}`}
                                    title={isCopied ? "Copied!" : "Copy Clause"}
                                >
                                    <Icon name={isCopied ? "CheckThick" : "Copy"} size={isCopied ? 20 : 14} />
                                </button>
                                {hasSubs && <Icon name="ChevronDown" size={12} className={`text-gray-400 mt-0.5 shrink-0 transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`}/>}
                            </div>
                        </div>
                        <div className="text-xs text-slate-500 dark:text-slate-400 italic mt-1.5 leading-relaxed block w-full whitespace-normal border-t border-gray-100 dark:border-slate-800 pt-1">
                            {c.description}
                        </div>
                    </div>
                </div>
                {/* Smooth Accordion Animation using Grid */}
                <div className={`grid transition-all duration-300 ease-in-out ${hasSubs && isExpanded ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'}`}>
                    <div className="overflow-hidden">
                        {hasSubs && <div className="mt-1 flex flex-col">{c.subClauses!.map(sub => renderClauseItem(sub, level + 1))}</div>}
                    </div>
                </div>
            </div>
        );
    };

    const renderClauses = () => {
        if (!standardKey || !standards[standardKey]) return <div className="text-center text-gray-400 mt-20 italic text-xs uppercase tracking-widest opacity-50">Select a Standard</div>;
        const data = standards[standardKey];

        const getGroupColorClass = (title: string) => {
            const t = title.toUpperCase();
            if (t.includes('PLAN')) return 'bg-blue-600 dark:bg-blue-500 shadow-blue-500/20';
            if (t.includes('SUPPORT')) return 'bg-purple-600 dark:bg-purple-500 shadow-purple-500/20';
            if (t.includes('DO')) return 'bg-orange-600 dark:bg-orange-500 shadow-orange-500/20';
            if (t.includes('CHECK') || t.includes('ACT')) return 'bg-emerald-600 dark:bg-emerald-500 shadow-emerald-500/20';
            if (t.includes('ANNEX')) return 'bg-rose-600 dark:bg-rose-500 shadow-rose-500/20';
            return 'bg-slate-800 dark:bg-slate-700';
        };

        return data.groups.map(g => {
            const isGroupExpanded = expandedGroups.includes(g.id) || !!searchQuery;
            const matchesSearch = (c: Clause): boolean => {
                const term = searchQuery.toLowerCase();
                return c.code.toLowerCase().includes(term) || c.title.toLowerCase().includes(term) || c.description.toLowerCase().includes(term) || (c.subClauses ? c.subClauses.some(matchesSearch) : false);
            };
            const filteredClauses = searchQuery ? g.clauses.filter(matchesSearch) : g.clauses;
            if (filteredClauses.length === 0) return null;

            return (
                <div key={g.id} className="mb-4 bg-white dark:bg-slate-900 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm overflow-hidden transition-all duration-300 hover:shadow-md">
                    <div className="flex items-center justify-between p-3.5 bg-gray-50/50 dark:bg-slate-800/30 cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors" onClick={() => toggleGroupExpand(g.id)}>
                        <div className="flex items-center gap-3">
                            <button 
                                onClick={(e) => { e.stopPropagation(); toggleGroupSelection(g); }}
                                className={`p-2 rounded-xl shadow-lg text-white ${getGroupColorClass(g.title)} hover:scale-110 active:scale-95 transition-transform duration-300`}
                                title="Click to Select/Deselect All in Group"
                            >
                                <Icon name={g.icon} size={14}/>
                            </button>
                            <h4 className="text-xs font-black text-slate-950 dark:text-white uppercase tracking-widest">{g.title}</h4>
                        </div>
                        <Icon name="ChevronDown" size={12} className={`text-slate-400 transition-transform duration-300 ${isGroupExpanded ? 'rotate-180' : ''}`}/>
                    </div>
                    <div className={`grid transition-all duration-300 ease-in-out ${isGroupExpanded ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'}`}>
                        <div className="overflow-hidden bg-white dark:bg-slate-900">
                             <div className="p-2 space-y-1">{filteredClauses.map(c => renderClauseItem(c))}</div>
                        </div>
                    </div>
                </div>
            );
        });
    };

    const auditFieldIconColor = "text-indigo-700 dark:text-indigo-400";
    const health = runHealthCheck();
    const isCustomStandard = !STANDARDS_DATA[standardKey] || (standards[standardKey] && standards[standardKey] !== STANDARDS_DATA[standardKey]);

    const standardOptions = (() => {
        const rawOptions = Object.keys(standards).map(k => ({ value: k, label: standards[k].name }));
        const seen = new Set();
        const unique = rawOptions.filter(item => {
            const duplicate = seen.has(item.label);
            seen.add(item.label);
            return !duplicate;
        });
        return [...unique, {value: "ADD_NEW", label: "+ Add New Standard..."}];
    })();

    // Helper for safe mobile width logic
    const isMobile = typeof window !== 'undefined' && window.innerWidth < 768;

    return (
        <div 
            ref={sidebarRef}
            className={`${isOpen ? 'border-r' : 'w-0 border-0 overflow-hidden'} flex flex-col bg-white dark:bg-slate-900 border-gray-200 dark:border-slate-800 shadow-2xl z-50 relative shrink-0 ${isResizing ? 'transition-none' : 'transition-[width] duration-500 ease-fluid-spring'} h-full`} 
            style={{ width: isOpen ? (isMobile ? '100%' : width) : 0 }}
        >
             {isOpen && <div className="absolute right-0 top-0 bottom-0 w-1.5 cursor-col-resize hover:bg-indigo-500 transition-colors z-50 group resize-handle hidden md:block" onMouseDown={startResizing} />}

            <div className={`flex-shrink-0 bg-white dark:bg-slate-900 w-full flex flex-col gap-3 transition-all duration-700 ease-fluid-spring overflow-hidden will-change-auto ${isHeaderVisible ? 'max-h-[1000px] opacity-100 p-5 border-b border-gray-100 dark:border-slate-800' : 'max-h-0 opacity-0 p-0 border-none'}`}>

                {/* Standard Selector */}
                <div className="relative">
                    <IconSelect 
                        icon="Book" 
                        iconColor={auditFieldIconColor} 
                        value={standardKey} 
                        onChange={(e: any) => { if (e.target.value === "ADD_NEW") onAddNewStandard(); else setStandardKey(e.target.value); }} 
                        options={standardOptions} 
                        defaultText="Select ISO Standard" 
                    />
                    {standardKey && (
                        <button onClick={() => setShowIntegrityModal(true)} className={`absolute -top-2 -right-2 p-1.5 rounded-full shadow-2xl transition-all duration-300 hover:scale-110 active:scale-95 text-white ring-4 ring-white dark:ring-slate-900 ${health.isHealthy ? 'bg-emerald-500' : 'bg-orange-500'}`} title="Standard Integrity Status">
                            <Icon name={health.isHealthy ? "CheckCircle2" : "AlertCircle"} size={14}/>
                        </button>
                    )}
                </div>

                {/* Audit Context */}
                <div className={`border rounded-xl overflow-hidden transition-all duration-300 ${
                    !isInfoExpanded 
                    ? 'border-gray-100 dark:border-slate-800 bg-white dark:bg-slate-900' 
                    : 'border-indigo-100 dark:border-slate-700 shadow-sm'
                }`}>
                    <button 
                        onClick={() => setIsInfoExpanded(!isInfoExpanded)}
                        className="w-full flex items-center justify-between p-3 transition-colors duration-300 hover:bg-gray-50 dark:hover:bg-slate-800/50"
                    >
                        <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                             <div className={`transition-all duration-300 ${isInfoExpanded ? 'text-indigo-500' : 'text-slate-400'}`}>
                                <Icon name="Info" size={14} />
                            </div>
                            Context & Details
                        </span>
                        <Icon name="ChevronDown" size={12} className={`text-slate-400 transition-transform duration-300 ${isInfoExpanded ? 'rotate-180' : ''}`}/>
                    </button>

                    <div className={`grid transition-all duration-300 ease-in-out ${isInfoExpanded ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'}`}>
                        <div className="overflow-hidden">
                             <div className="p-3 bg-gray-50/50 dark:bg-slate-900/50 space-y-3 border-t border-gray-100 dark:border-slate-800">
                                <IconSelect icon="FileEdit" iconColor={auditFieldIconColor} value={auditInfo.type} onChange={(e: any) => setAuditInfo({...auditInfo, type: e.target.value})} options={Object.keys(AUDIT_TYPES).map(key => ({ value: key, label: key }))} defaultText="Select Audit Type" />
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                                    <IconInput icon="Building" iconColor={auditFieldIconColor} placeholder="Company Name" value={auditInfo.company} onChange={(e: any) => setAuditInfo({...auditInfo, company: e.target.value})} />
                                    <IconInput icon="Tag" iconColor={auditFieldIconColor} placeholder="# SMO" value={auditInfo.smo} onChange={(e: any) => setAuditInfo({...auditInfo, smo: e.target.value})} />
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                                    <IconInput icon="Users" iconColor={auditFieldIconColor} placeholder="Department" value={auditInfo.department} onChange={(e: any) => setAuditInfo({...auditInfo, department: e.target.value})} />
                                    <IconInput icon="User" iconColor={auditFieldIconColor} placeholder="Auditee/Auditor" value={auditInfo.interviewee} onChange={(e: any) => setAuditInfo({...auditInfo, interviewee: e.target.value})} />
                                    <IconInput icon="AuditUser" iconColor={auditFieldIconColor} placeholder="Lead Auditor Name" value={auditInfo.auditor} onChange={(e: any) => setAuditInfo({...auditInfo, auditor: e.target.value})} />
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <div className="flex-1 flex flex-col min-h-0 bg-gray-50/40 dark:bg-slate-950/40 w-full">
                <div className={`p-3 border-b border-gray-100 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-10 sticky top-0 transition-all duration-500 ${!isHeaderVisible ? 'shadow-md border-indigo-100 dark:border-indigo-900/50' : ''}`}>
                    <div className="flex items-center gap-2">
                        <div className="relative flex-1 flex items-center gap-1 bg-gray-100 dark:bg-slate-800 rounded-xl px-2 transition-all focus-within:ring-2 focus-within:ring-indigo-500/20">
                            <span className="text-blue-700 dark:text-blue-400 font-bold pl-1"><Icon name="Search" size={14}/></span>
                            <input className="w-full bg-transparent py-2 px-1 text-xs font-medium outline-none text-slate-800 dark:text-slate-200 placeholder-gray-400" placeholder="Search content..." value={searchQueryRaw} onChange={e => setSearchQueryRaw(e.target.value)}/>

                            <button 
                                onClick={toggleExpandAll} 
                                className="p-1.5 rounded-lg hover:bg-white dark:hover:bg-slate-700 text-slate-400 hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors"
                                title={areAllGroupsExpanded ? "Collapse All Groups" : "Expand All Groups"}
                            >
                                <Icon name={areAllGroupsExpanded ? "CollapsePanel" : "ExpandPanel"} size={14}/>
                            </button>
                        </div>

                        {selectedClauses.length > 0 && (
                            <div className="flex gap-2 animate-in fade-in slide-in-from-right-5 duration-300">
                                <button onClick={handleCopySelectedClauses} className="p-2 rounded-xl bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 hover:bg-indigo-100 transition-colors relative shadow-sm border border-indigo-100 dark:border-indigo-900/30 hover:scale-105" title="Copy Selected Clauses">
                                    <Icon name="Copy" size={16} />
                                </button>
                                <button onClick={() => setSelectedClauses([])} className="p-2 rounded-xl bg-red-50 dark:bg-red-900/20 text-red-600 hover:bg-red-100 transition-colors relative shadow-sm border border-red-100 dark:border-red-900/30 hover:scale-105" title="Clear All">
                                    <Icon name="Trash2" size={16} />
                                    <div className="absolute -top-1 -right-1 bg-red-600 text-white text-[9px] font-black w-4 h-4 rounded-full flex items-center justify-center border-2 border-white dark:border-slate-900 shadow-sm animate-bounce">{selectedClauses.length}</div>
                                </button>
                            </div>
                        )}
                    </div>
                </div>
                <div 
                    ref={scrollContainerRef}
                    className="flex-1 overflow-y-auto custom-scrollbar p-3 scroll-smooth"
                    onScroll={handleScroll}
                >
                    <div className="min-h-[150vh] flex flex-col">
                        {renderClauses()}
                        <div className="flex-1"></div> {/* Spacer to fill remaining height */}
                    </div>
                </div>
            </div>

            <Modal isOpen={showIntegrityModal} title="Standard Health Index" onClose={() => setShowIntegrityModal(false)}>
                 <div className="space-y-6">
                    <div className="flex items-center gap-5 p-5 rounded-3xl bg-gray-50 dark:bg-slate-800 border border-gray-100 dark:border-slate-700 shadow-inner">
                        <div className={`w-20 h-20 rounded-full flex items-center justify-center text-white text-2xl font-black shadow-xl ring-4 ring-white dark:ring-slate-700 ${health.score > 90 ? 'bg-gradient-to-br from-emerald-400 to-emerald-600' : 'bg-gradient-to-br from-orange-400 to-orange-600'}`}>
                            {health.score}%
                        </div>
                        <div className="flex-1">
                            <h4 className="font-black text-slate-900 dark:text-slate-100 uppercase tracking-tight">Data Health</h4>
                            <p className="text-xs text-slate-500 dark:text-slate-400 leading-snug mt-1">{health.isHealthy ? 'Excellent! Data is accurate, clean, and complete for professional use.' : 'Standard data is incomplete or contains errors. Please review.'}</p>
                        </div>
                    </div>
                    <div className="space-y-3">
                        <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Integrity Checklist</h5>
                        {health.integrity.map((item, idx) => (
                            <div key={idx} className="flex items-center justify-between p-4 bg-white dark:bg-slate-900 border border-gray-100 dark:border-slate-800 rounded-2xl shadow-sm">
                                <div className="flex items-center gap-4">
                                    <div className={`p-1.5 rounded-full shadow-sm ${item.status === 'pass' ? 'text-emerald-500 bg-emerald-50 dark:bg-emerald-900/20' : 'text-red-500 bg-red-50 dark:bg-red-900/20'}`}>
                                        <Icon name={item.status === 'pass' ? "CheckCircle2" : "AlertCircle"} size={18}/>
                                    </div>
                                    <span className="text-sm font-bold text-slate-700 dark:text-slate-200">{item.label}</span>
                                </div>
                                <span className={`text-[10px] font-black px-3 py-1 rounded-full shadow-sm uppercase ${item.status === 'pass' ? 'text-emerald-700 bg-emerald-100' : 'text-red-700 bg-red-100'}`}>
                                    {item.detail}
                                </span>
                            </div>
                        ))}
                    </div>
                     <div className="mt-6 pt-4 border-t border-gray-100 dark:border-slate-700 flex justify-end gap-3">
                     {isCustomStandard && (
                        <button 
                            onClick={() => {
                                if(confirm("Are you sure? This will remove all AI repairs and revert to the original static data.")) {
                                    onResetStandard(standardKey);
                                    setShowIntegrityModal(false);
                                    setRepairStats(null);
                                    setRepairedIds([]);
                                }
                            }} 
                            className="px-4 py-2 bg-red-50 hover:bg-red-100 text-red-600 dark:bg-red-900/20 dark:hover:bg-red-900/40 dark:text-red-400 rounded-xl font-bold text-xs flex items-center gap-2 transition-all active:scale-95 border border-red-200 dark:border-red-800"
                        >
                            <Icon name="Trash2" size={14}/>
                            Reset to Default
                        </button>
                     )}

                     {repairStats ? (
                         <div className="flex items-center gap-3 animate-in fade-in slide-in-from-right-5">
                            <div className="text-right">
                                <p className="text-[10px] font-bold text-emerald-600 uppercase">Repair Complete</p>
                                <p className="text-xs text-slate-500">Added {repairStats.fixed} items, Cleaned {repairStats.cleaned} dupes.</p>
                            </div>
                            <button onClick={() => setShowIntegrityModal(false)} className="px-4 py-2 bg-emerald-500 hover:bg-emerald-600 text-white rounded-xl font-bold text-xs shadow-lg shadow-emerald-500/30">
                                Close & Continue
                            </button>
                         </div>
                     ) : !health.isHealthy && (
                         <button 
                            onClick={handleAutoRepair} 
                            disabled={isRepairing}
                            className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold text-xs flex items-center gap-2 shadow-lg shadow-indigo-500/30 transition-all active:scale-95 disabled:opacity-70 disabled:active:scale-100"
                        >
                            {isRepairing ? <Icon name="Loader" className="animate-spin"/> : <Icon name="Wand2"/>}
                            {isRepairing ? "AI is Fixing..." : "Auto-Repair Issues with AI"}
                        </button>
                     )}
                 </div>
                 </div>
            </Modal>
        </div>
    );
};
export default Sidebar;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { APP_VERSION, STANDARDS_DATA, INITIAL_EVIDENCE, MODEL_HIERARCHY } from './constants';
import { StandardsData, AuditInfo, AnalysisResult, Standard, Clause, FindingsViewMode, FindingStatus } from './types';
import { Icon, FontSizeController, SparkleLoader, Modal, AINeuralLoader, Toast, CommandPaletteModal } from './components/UI';
import Sidebar from './components/Sidebar';
import ReleaseNotesModal from './components/ReleaseNotesModal';
import { generateOcrContent, generateAnalysis, generateTextReport } from './services/geminiService';
import { cleanAndParseJSON, fileToBase64 } from './utils';
import { useGeminiSystem } from './hooks/useGeminiSystem';
import { useSmartExport } from './hooks/useSmartExport';

declare var mammoth: any;

type LayoutMode = 'evidence' | 'findings' | 'report' | 'split';
type ExportLanguage = 'en' | 'vi';

function App() {
    // -- CORE HOOKS --
    const gemini = useGeminiSystem();
    const smartExport = useSmartExport(gemini.executeWithSmartFailover, gemini.setApiKeys, gemini.setActiveKeyId);

    // -- STATE --
    const [fontSizeScale, setFontSizeScale] = useState(1.0);
    const [isDarkMode, setIsDarkMode] = useState(true);
    const [sidebarWidth, setSidebarWidth] = useState(390);
    const [isSidebarOpen, setIsSidebarOpen] = useState(true);
    const [showAboutModal, setShowAboutModal] = useState(false);
    const [showSettingsModal, setShowSettingsModal] = useState(false);

    // Feature: Command Palette & View Modes
    const [isCmdPaletteOpen, setIsCmdPaletteOpen] = useState(false);
    const [findingsViewMode, setFindingsViewMode] = useState<FindingsViewMode>('list');
    const [newKeyInput, setNewKeyInput] = useState("");
    const [newKeyLabel, setNewKeyLabel] = useState("");

    // Feedback State
    const [toastMsg, setToastMsg] = useState<string | null>(null);
    const [aiError, setAiError] = useState<string | null>(null);
    const [loadingMessage, setLoadingMessage] = useState<string>(""); 

    // Session Data
    const [exportLanguage, setExportLanguage] = useState<ExportLanguage>('en');
    const [notesLanguage, setNotesLanguage] = useState<ExportLanguage>('vi'); 
    const [evidenceLanguage, setEvidenceLanguage] = useState<ExportLanguage>('en'); 
    const [isDragging, setIsDragging] = useState(false);

    const [reportTemplate, setReportTemplate] = useState<string>("");
    const [templateFileName, setTemplateFileName] = useState<string>("");

    const [customStandards, setCustomStandards] = useState<StandardsData>(STANDARDS_DATA);
    const [standardKey, setStandardKey] = useState<string>("ISO 9001:2015");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>({ company: "", smo: "", department: "", interviewee: "", auditor: "", type: "" });
    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [pastedImages, setPastedImages] = useState<File[]>([]);

    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [finalReportText, setFinalReportText] = useState<string | null>(null);
    const [layoutMode, setLayoutMode] = useState('evidence' as LayoutMode);

    // Loading Flags
    const [isOcrLoading, setIsOcrLoading] = useState(false);
    const [isAnalyzeLoading, setIsAnalyzeLoading] = useState(false);
    const [currentAnalyzingClause, setCurrentAnalyzingClause] = useState<string>(""); 
    const [isReportLoading, setIsReportLoading] = useState(false);

    const [logoKey, setLogoKey] = useState(0);

    // Fluid Tab State
    const [tabStyle, setTabStyle] = useState({ left: 0, width: 0, opacity: 0, color: '' });
    const tabsRef = useRef<(HTMLButtonElement | null)[]>([]);
    const tabsContainerRef = useRef<HTMLDivElement>(null); 

    const tabsList = [
        { id: 'evidence', label: '1. Evidence', icon: 'ScanText', colorClass: 'bg-blue-500', textClass: 'text-blue-600', borderClass: 'border-blue-500', bgSoft: 'bg-blue-50 dark:bg-blue-900/10' }, 
        { id: 'findings', label: '2. Findings', icon: 'Wand2', colorClass: 'bg-purple-500', textClass: 'text-purple-600', borderClass: 'border-purple-500', bgSoft: 'bg-purple-50 dark:bg-purple-900/10' }, 
        { id: 'report', label: '3. Report', icon: 'FileText', colorClass: 'bg-emerald-500', textClass: 'text-emerald-600', borderClass: 'border-emerald-500', bgSoft: 'bg-emerald-50 dark:bg-emerald-900/10' }
    ];
    const currentTabConfig = tabsList.find(t => t.id === layoutMode) || tabsList[0];

    const fileInputRef = useRef<HTMLInputElement>(null);
    const evidenceTextareaRef = useRef<HTMLTextAreaElement>(null);
    const findingsContainerRef = useRef<HTMLDivElement>(null);

    const allStandards = { ...STANDARDS_DATA, ...customStandards };
    const hasEvidence = evidence.trim().length > 0 || pastedImages.length > 0;
    const isReadyForAnalysis = !isAnalyzeLoading && selectedClauses.length > 0 && hasEvidence;

    // --- UTILS ---
    const insertTextAtCursor = (textToInsert: string) => {
        if (evidenceTextareaRef.current) {
            const textarea = evidenceTextareaRef.current;
            const start = textarea.selectionStart;
            const end = textarea.selectionEnd;
            const newValue = evidence.substring(0, start) + textToInsert + evidence.substring(end);
            setEvidence(newValue);
            if (layoutMode !== 'evidence') setLayoutMode('evidence');
            setTimeout(() => {
                if (evidenceTextareaRef.current) {
                    evidenceTextareaRef.current.focus();
                    evidenceTextareaRef.current.setSelectionRange(start + textToInsert.length, start + textToInsert.length);
                }
            }, 100);
        } else {
            setEvidence(prev => prev + "\n" + textToInsert);
            if (layoutMode !== 'evidence') setLayoutMode('evidence');
        }
    };

    // --- EFFECTS ---
    useEffect(() => {
        const storedScale = localStorage.getItem('iso_font_scale');
        if (storedScale) setFontSizeScale(parseFloat(storedScale));

        loadSessionData();
        const savedDarkMode = localStorage.getItem('iso_dark_mode');
        if (savedDarkMode !== null) setIsDarkMode(savedDarkMode === 'true');
        else setIsDarkMode(true); 

        // Fix Sidebar logic: If mobile, hide it initially
        if (window.innerWidth < 768) setIsSidebarOpen(false);
    }, []);

    useEffect(() => {
        const updateTabs = () => {
            const activeIndex = tabsList.findIndex(t => t.id === layoutMode);
            const el = tabsRef.current[activeIndex];
            if (el) setTabStyle({ left: el.offsetLeft, width: el.offsetWidth, opacity: 1, color: tabsList[activeIndex].colorClass });
        };
        updateTabs();
        const t = setTimeout(updateTabs, 50);
        const observer = new ResizeObserver(() => updateTabs());
        if (tabsContainerRef.current) observer.observe(tabsContainerRef.current);
        return () => { clearTimeout(t); observer.disconnect(); };
    }, [layoutMode, sidebarWidth, fontSizeScale]); 

    useEffect(() => {
        if (smartExport.exportState.isFinished && smartExport.exportState.isOpen) {
            smartExport.downloadExportFile(standardKey, auditInfo);
        }
    }, [smartExport.exportState.isFinished]);

    useEffect(() => {
        if (layoutMode === 'findings' && findingsContainerRef.current) {
            findingsContainerRef.current.scrollTop = findingsContainerRef.current.scrollHeight;
        }
    }, [analysisResult]);

    const loadSessionData = () => {
        try {
            const savedAuditInfo = localStorage.getItem("iso_audit_info");
            const savedEvidence = localStorage.getItem("iso_evidence");
            const savedStandardKey = localStorage.getItem("iso_standard_key");
            const savedSelectedClauses = localStorage.getItem("iso_selected_clauses");
            const savedTemplate = localStorage.getItem('iso_report_template');
            const savedTemplateName = localStorage.getItem('iso_report_template_name');

            if (savedAuditInfo) setAuditInfo(JSON.parse(savedAuditInfo));
            if (savedEvidence && savedEvidence.trim() !== '') setEvidence(savedEvidence);
            if (savedStandardKey) setStandardKey(savedStandardKey);
            if (savedSelectedClauses) setSelectedClauses(JSON.parse(savedSelectedClauses));
            if (savedTemplate) setReportTemplate(savedTemplate);
            if (savedTemplateName) setTemplateFileName(savedTemplateName);
        } catch (e) { console.error("Failed to load session data", e); }
    };

    useEffect(() => {
        if (isDarkMode) document.body.classList.add('dark'); else document.body.classList.remove('dark');
        localStorage.setItem('iso_dark_mode', String(isDarkMode));
    }, [isDarkMode]);

    useEffect(() => {
        document.documentElement.style.setProperty('--font-scale', fontSizeScale.toString());
        localStorage.setItem('iso_font_scale', fontSizeScale.toString());
    }, [fontSizeScale]);

    useEffect(() => { localStorage.setItem("iso_audit_info", JSON.stringify(auditInfo)); }, [auditInfo]);
    useEffect(() => { localStorage.setItem("iso_evidence", evidence); }, [evidence]);
    useEffect(() => { localStorage.setItem("iso_standard_key", standardKey); }, [standardKey]);
    useEffect(() => { localStorage.setItem("iso_selected_clauses", JSON.stringify(selectedClauses)); }, [selectedClauses]);
    useEffect(() => {
        localStorage.setItem('iso_report_template', reportTemplate);
        localStorage.setItem('iso_report_template_name', templateFileName);
    }, [reportTemplate, templateFileName]);

    // --- HANDLERS ---
    const handleNewSession = () => {
        if (window.confirm("Start new session? Current work will be cleared.")) {
            setAuditInfo({ company: "", smo: "", department: "", interviewee: "", auditor: "", type: "" });
            setSelectedClauses([]);
            setEvidence(INITIAL_EVIDENCE);
            setPastedImages([]);
            setAnalysisResult(null);
            setSelectedFindings({});
            setFinalReportText(null);
            setLayoutMode('evidence');
            setAiError(null);
        }
    };

    const handleUpdateStandard = (updated: Standard) => setCustomStandards(prev => ({ ...prev, [standardKey]: updated }));
    const handleResetStandard = (key: string) => { setCustomStandards(prev => { const next = { ...prev }; delete next[key]; return next; }); };

    const loadStressTestData = () => {
        setAuditInfo({ company: "TechCorp Global", smo: "TC-2024-ISO-001", department: "IT Ops", interviewee: "John Smith", auditor: "Trung Dang", type: "Stage 2" });
        setStandardKey("ISO 27001:2022 (ISMS)");
        setSelectedClauses(["5.1", "6.1.2", "A.5.9", "9.2"]);
        setEvidence(`AUDIT EVIDENCE TEST...\n[5.1] Leadership committed. Policy approved.\n[A.5.9] Assets reviewed. 5 laptops checked. 1 missing tag.`);
        setToastMsg("Stress Test Data Loaded!");
        setLayoutMode('evidence');
    };

    const handleRecall = () => { loadSessionData(); setToastMsg("Session Recalled Successfully"); };

    const handleTemplateUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        setTemplateFileName(file.name);
        if (file.name.endsWith('.docx')) {
            const arrayBuffer = await file.arrayBuffer();
            mammoth.extractRawText({ arrayBuffer }).then((result: any) => setReportTemplate(result.value)).catch((err: any) => console.error(err));
        } else {
            const reader = new FileReader();
            reader.onload = (re) => setReportTemplate(re.target?.result as string);
            reader.readAsText(file);
        }
    };

    const handlePaste = (e: React.ClipboardEvent) => {
        const items = e.clipboardData.items;
        const newImages: File[] = [];
        for (let i = 0; i < items.length; i++) {
            if (items[i].type.indexOf("image") !== -1) {
                const blob = items[i].getAsFile();
                if (blob) newImages.push(blob);
            }
        }
        if (newImages.length > 0) setPastedImages(prev => [...prev, ...newImages]);
    };

    const handleUpdateFinding = (index: number, field: keyof AnalysisResult, value: string) => {
        setAnalysisResult(prev => {
            if (!prev) return null;
            const newArr = [...prev];
            newArr[index] = { ...newArr[index], [field]: value };
            return newArr;
        });
    };

    // --- AI HANDLERS ---
    const handleAnalyze = async () => {
        if (!hasEvidence || selectedClauses.length === 0) return;
        setIsAnalyzeLoading(true); setAiError(null); setAnalysisResult([]); setLayoutMode('findings'); setLoadingMessage("Initializing AI Auditor...");

        try {
            const scopeClauses = allStandards[standardKey].groups.flatMap(g => g.clauses).filter(c => selectedClauses.includes(c.id));

            for (let i = 0; i < scopeClauses.length; i++) {
                const clause = scopeClauses[i];
                setCurrentAnalyzingClause(clause.code); setLoadingMessage(`Analyzing Clause ${clause.code}...`);

                const prompt = `Act as an ISO Lead Auditor. Evaluate compliance for this SINGLE clause:
                [${clause.code}] ${clause.title}: ${clause.description}
                CONTEXT: ${auditInfo.type} for ${auditInfo.company}.
                RAW EVIDENCE: """ ${evidence} """
                Return a JSON Array with exactly ONE object containing: clauseId (must be "${clause.id}"), status (COMPLIANT, NC_MAJOR, NC_MINOR, OFI), reason, suggestion, evidence, conclusion_report (concise).`;

                try {
                    const resultStr = await gemini.executeWithSmartFailover(async (key, model) => {
                        return await generateAnalysis(prompt, `Output JSON array only.`, key, model);
                    });
                    const chunkResult = cleanAndParseJSON(resultStr || "");
                    if (chunkResult && Array.isArray(chunkResult) && chunkResult.length > 0) {
                        const resultItem = chunkResult[0];
                        resultItem.clauseId = clause.id;
                        setAnalysisResult(prev => {
                            const prevSafe = prev || [];
                            if (prevSafe.find(r => r.clauseId === resultItem.clauseId)) return prevSafe;
                            setSelectedFindings(sel => ({...sel, [resultItem.clauseId]: true}));
                            return [...prevSafe, resultItem];
                        });
                    }
                } catch (innerError: any) {
                    if (innerError.message === "ALL_RESOURCES_EXHAUSTED" || innerError.message === "ALL_KEYS_EXHAUSTED") throw innerError; 
                    console.error(`Failed to analyze clause ${clause.code}`, innerError);
                }
                await new Promise(r => setTimeout(r, 200));
            }
        } catch (e: any) { 
            if (e.message === "ALL_KEYS_EXHAUSTED" || e.message === "ALL_RESOURCES_EXHAUSTED") {
                setAiError("System Overload: All API Keys and Model Backups are exhausted.");
                setShowSettingsModal(true); 
            } else setAiError(e.message || "Analysis Failed");
        } finally { 
            setIsAnalyzeLoading(false); setCurrentAnalyzingClause(""); setLoadingMessage("");
        }
    };

    const handleGenerateReport = async () => {
        if (!analysisResult) return;
        setIsReportLoading(true); setLayoutMode('report'); setAiError(null);
        setLoadingMessage(!!reportTemplate ? `Analyzing Template...` : "Synthesizing Report...");

        try {
             const acceptedFindings = analysisResult.filter(r => selectedFindings[r.clauseId]);
             let prompt = !!reportTemplate ? `ROLE: ISO Lead Auditor. TASK: Follow TEMPLATE structure strictly.\nTEMPLATE:\n"""${reportTemplate}"""\nDATA: Context: ${JSON.stringify(auditInfo)}, Findings: ${JSON.stringify(acceptedFindings)}` : `GENERATE FINAL REPORT. DATA: ${JSON.stringify(auditInfo)}. FINDINGS: ${JSON.stringify(acceptedFindings)}.`;
             const text = await gemini.executeWithSmartFailover(async (key, model) => await generateTextReport(prompt, "Expert ISO Report Compiler.", key, model));
             setFinalReportText(text || "");
        } catch (e: any) { 
            if (e.message === "ALL_KEYS_EXHAUSTED" || e.message === "ALL_RESOURCES_EXHAUSTED") {
                setAiError("API Quota Exceeded during report generation."); setShowSettingsModal(true);
            } else setAiError(e.message || "Report Generation Failed"); 
        } finally { setIsReportLoading(false); setLoadingMessage(""); }
    };

    const handleOcrUpload = async () => {
        if (pastedImages.length === 0) return;
        setIsOcrLoading(true); setAiError(null);
        try {
            const promises = pastedImages.map(async (file) => {
                const b64 = await fileToBase64(file);
                return await gemini.executeWithSmartFailover(async (key, model) => await generateOcrContent("Extract text accurately.", b64, file.type, key, model));
            });
            const results = await Promise.all(promises);
            insertTextAtCursor(results.join('\n\n'));
            setPastedImages([]);
        } catch (e: any) { setAiError(e.message || "OCR Processing Failed"); } finally { setIsOcrLoading(false); }
    };

    const handleDragOver = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(true); };
    const handleDrop = (e: React.DragEvent) => {
        e.preventDefault(); setIsDragging(false);
        const files = Array.from(e.dataTransfer.files);
        if (files.length > 0) setPastedImages(prev => [...prev, ...files]);
    };

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if ((e.metaKey || e.ctrlKey) && e.key === 'k') { e.preventDefault(); setIsCmdPaletteOpen(prev => !prev); }
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, []);

    const commandActions = useMemo(() => {
        const actions: any[] = [
            { label: "Analyze Compliance", desc: "Start AI analysis", icon: "Wand2", shortcut: "AI", action: handleAnalyze },
            { label: "Toggle Dark Mode", desc: `Switch to ${isDarkMode ? 'Light' : 'Dark'}`, icon: isDarkMode ? "Sun" : "Moon", action: () => setIsDarkMode(!isDarkMode) },
            { label: "Generate Report", desc: "Synthesize final report", icon: "FileText", action: handleGenerateReport },
            { label: "Export Notes", desc: "Download findings", icon: "Download", action: () => {
                 const reportTxt = analysisResult?.filter(r => selectedFindings[r.clauseId]).map(r => `[${r.status}] Clause ${r.clauseId}: ${r.conclusion_report}`).join('\n\n') || "";
                 smartExport.startSmartExport(reportTxt, 'notes', notesLanguage);
            }},
            { label: "Dev: Load Stress Test Data", desc: "Populate complex audit data", icon: "Database", action: loadStressTestData },
            { label: "Settings / API Key", desc: "Manage configuration", icon: "Settings", action: () => setShowSettingsModal(true) },
        ];
        if (allStandards[standardKey]) {
            const flatten = (list: Clause[]): any[] => list.flatMap(c => {
                const item = { label: `${c.code} ${c.title}`, desc: c.description, type: 'clause', icon: 'Book', action: () => insertTextAtCursor(`[${c.code}] ${c.title}`) };
                return c.subClauses ? [item, ...flatten(c.subClauses)] : [item];
            });
            return [...actions, ...allStandards[standardKey].groups.flatMap(g => flatten(g.clauses))];
        }
        return actions;
    }, [isDarkMode, standardKey, allStandards, analysisResult, selectedFindings]);

    const getAnalyzeTooltip = () => {
        if (isAnalyzeLoading) return "AI is analyzing...";
        const missing = [];
        if (selectedClauses.length === 0) missing.push("Clauses");
        if (!hasEvidence) missing.push("Evidence");
        if (missing.length > 0) return `Feature Unavailable. Missing: ${missing.join(" & ")}.`;
        return "Ready! Click to Start AI Analysis.";
    };

    return (
        <div className="flex flex-col h-[100dvh] w-full bg-gray-50 dark:bg-slate-900 transition-colors duration-500 ease-soft relative">
            {toastMsg && <Toast message={toastMsg} onClose={() => setToastMsg(null)} />}
            {aiError && (
                <div className="fixed top-20 right-5 z-[9999] max-w-sm w-full bg-white dark:bg-slate-800 border-l-4 border-red-500 shadow-2xl rounded-r-xl p-4 animate-in slide-in-from-right-10 flex flex-col gap-2">
                    <div className="flex justify-between items-start"><div className="flex items-center gap-2 text-red-600 dark:text-red-400 font-bold"><Icon name="AlertCircle" size={20}/><span>System Alert</span></div><button onClick={() => setAiError(null)} className="text-gray-400 hover:text-slate-800 dark:hover:text-white"><Icon name="X" size={18}/></button></div>
                    <p className="text-sm text-slate-600 dark:text-slate-300 leading-relaxed">{aiError}</p>
                </div>
            )}
            {/* HEADER */}
            <div className="flex-shrink-0 px-4 md:px-6 py-0 border-b border-gray-200 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-[70] relative flex justify-between items-center h-16">
                <div className="flex items-center h-full gap-3 md:gap-5">
                    <div className={`relative group cursor-pointer flex items-center justify-center`} onClick={() => { setIsSidebarOpen(!isSidebarOpen); setLogoKey(prev => prev + 1); }}>
                        <div className="relative w-10 h-10 md:w-14 md:h-14 flex items-center justify-center">
                            <div className="absolute -inset-4 bg-indigo-500/0 rounded-full blur-xl group-hover:bg-indigo-500/10 transition-all"></div>
                            <div className="absolute -inset-1 rounded-full bg-[conic-gradient(from_0deg,transparent_0_deg,#f472b6_100deg,#8b5cf6_200deg,#06b6d4_300deg,transparent_360deg)] opacity-30 blur-lg animate-[spin_4s_linear_infinite] group-hover:opacity-70 group-hover:blur-md transition-all"></div>
                            <div className="relative z-10">{isSidebarOpen ? <div className="relative w-8 h-8"><div className="absolute inset-0 border-2 border-transparent border-t-indigo-500 border-b-cyan-500 rounded-full animate-infinity-spin"></div><div className="absolute inset-2 border-2 border-transparent border-l-purple-500 border-r-pink-500 rounded-full animate-spin-reverse"></div></div> : <div className="hover:scale-110 transition-transform"><Icon name="TDLogo" size={32} /></div>}</div>
                        </div>
                    </div>
                    <div className="flex items-center gap-2 md:gap-3">
                        <h1 className="hidden md:block text-lg font-bold tracking-tight text-slate-900 dark:text-white leading-none">ISO Audit <span className="font-light text-slate-400">Pro</span></h1>
                        <div className="hidden md:block h-5 w-px bg-gray-200 dark:bg-slate-700 mx-1"></div>
                        <div className="flex items-center"><span className="text-[11px] font-bold text-indigo-600 dark:text-indigo-300 bg-indigo-50 dark:bg-indigo-900/30 px-3 py-1 rounded-full border border-indigo-100 dark:border-indigo-800/50 uppercase tracking-wider hidden sm:block">{allStandards[standardKey]?.name.split(' ')[1] || 'ISO'}</span></div>
                    </div>
                </div>
                <div className="flex items-center gap-2">
                    <button onClick={() => setIsCmdPaletteOpen(true)} className="p-2 rounded-lg text-slate-500 hover:text-indigo-600 dark:text-slate-400 dark:hover:text-indigo-400 hover:bg-gray-100 dark:hover:bg-slate-800 transition-all"><Icon name="Search" size={20}/></button>
                    <div className="hidden lg:block"><FontSizeController fontSizeScale={fontSizeScale} adjustFontSize={(dir: any) => setFontSizeScale(prev => dir === 'increase' ? Math.min(prev + 0.1, 1.3) : Math.max(prev - 0.1, 0.8))} /></div>
                    <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-2 rounded-lg text-slate-500 hover:text-slate-900 dark:text-slate-400 dark:hover:text-white hover:bg-gray-100 dark:hover:bg-slate-800 transition-all"><Icon name={isDarkMode ? "Sun" : "Moon"} size={18}/></button>
                    <div className="hidden md:block h-4 w-px bg-gray-200 dark:bg-slate-800 mx-1"></div>
                    <button onClick={() => setShowSettingsModal(true)} className="group relative w-8 h-8 flex items-center justify-center transition-all"><div className={`absolute inset-0 rounded-full opacity-20 animate-ping ${gemini.activeKeyId ? 'bg-emerald-500' : 'bg-red-500'}`}></div><div className={`relative w-2.5 h-2.5 rounded-full ring-2 ring-white dark:ring-slate-900 ${gemini.activeKeyId ? 'bg-emerald-500' : 'bg-red-500'}`}></div></button>
                    <button onClick={() => setShowAboutModal(true)} className="ml-1 p-2 text-slate-400 hover:text-indigo-600 transition-colors"><Icon name="Info" size={18}/></button>
                </div>
            </div>

            <div className="flex-1 flex overflow-hidden relative">
                <div className={`${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} fixed top-16 bottom-0 left-0 z-[60] md:absolute md:inset-y-0 md:relative md:top-0 md:translate-x-0 transition-transform duration-500 ease-fluid-spring h-[calc(100%-4rem)] md:h-full`}>
                    <Sidebar isOpen={isSidebarOpen} width={sidebarWidth} setWidth={setSidebarWidth} standards={allStandards} standardKey={standardKey} setStandardKey={setStandardKey} auditInfo={auditInfo} setAuditInfo={setAuditInfo} selectedClauses={selectedClauses} setSelectedClauses={setSelectedClauses} onAddNewStandard={() => { const name = prompt("Enter new Standard Name:"); if(name) setCustomStandards(prev => ({...prev, [name]: { name, description: "Custom", groups: [] }})); }} onUpdateStandard={handleUpdateStandard} onResetStandard={handleResetStandard}/>
                </div>
                {isSidebarOpen && <div className="fixed top-16 bottom-0 inset-x-0 bg-black/50 z-50 md:hidden backdrop-blur-sm" onClick={() => setIsSidebarOpen(false)}/>}

                <div className={`flex-1 flex flex-col min-w-0 transition-all duration-500 relative w-full ${isDragging ? 'ring-4 ring-indigo-500/50 scale-[0.99]' : ''} ${currentTabConfig.bgSoft} border-t-4 ${currentTabConfig.borderClass}`} onDragOver={handleDragOver} onDragLeave={() => setIsDragging(false)} onDrop={handleDrop}>
                    {isDragging && <div className="absolute inset-0 z-50 flex items-center justify-center bg-indigo-500/10 backdrop-blur-sm m-4 pointer-events-none rounded-3xl border-4 border-dashed border-indigo-500"><div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-2xl flex flex-col items-center animate-bounce"><Icon name="UploadCloud" size={48} className="text-indigo-500 mb-4"/><h3 className="text-2xl font-black text-indigo-600">Drop Evidence</h3></div></div>}

                    <div className="flex-shrink-0 px-4 md:px-6 py-4 border-b border-gray-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur flex justify-between items-center gap-3">
                        <div className="flex-1 min-w-0">
                            <div ref={tabsContainerRef} className="relative flex justify-between bg-gray-100 dark:bg-slate-800 p-1 rounded-xl w-full">
                                <div className={`absolute top-1 bottom-1 shadow-sm rounded-lg transition-all duration-500 ease-fluid-spring z-0 ${tabStyle.color}`} style={{ left: tabStyle.left, width: tabStyle.width, opacity: tabStyle.opacity }}/>
                                {tabsList.map((tab, idx) => (<button key={tab.id} ref={el => { tabsRef.current[idx] = el; }} onClick={() => setLayoutMode(tab.id as LayoutMode)} className={`flex-1 relative z-10 flex items-center justify-center gap-2 px-1 md:px-4 py-2 rounded-lg text-xs md:text-sm font-bold transition-colors ${layoutMode === tab.id ? 'text-white' : 'text-slate-500'}`}><Icon name={tab.icon} size={16}/><span className={`${isSidebarOpen ? 'hidden xl:inline' : 'hidden md:inline'}`}>{tab.label}</span></button>))}
                            </div>
                        </div>
                        <div className="flex gap-2 items-center flex-shrink-0 pl-2 border-l border-gray-200 dark:border-slate-800">
                            <button onClick={handleRecall} className="p-3 bg-gray-100 dark:bg-slate-800 hover:bg-gray-200 text-slate-600 dark:text-slate-300 rounded-xl transition-all hover:scale-105"><Icon name="History" size={18}/></button>
                            <button onClick={handleNewSession} className="p-3 bg-gray-100 dark:bg-slate-800 hover:bg-gray-200 text-slate-600 dark:text-slate-300 rounded-xl transition-all hover:text-indigo-600 hover:scale-105"><Icon name="Session4_FilePlus" size={18}/></button>
                        </div>
                    </div>

                    <div className="flex-1 overflow-hidden relative p-4 md:p-6">
                        {layoutMode === 'evidence' && (
                            <div className="h-full flex flex-col gap-4 animate-fade-in-up relative">
                                <div className="flex-1 flex flex-col gap-4 min-h-0">
                                    <div className="flex-1 bg-white dark:bg-slate-900 rounded-3xl shadow-sm border border-gray-100 dark:border-slate-800 overflow-hidden flex flex-col relative group focus-within:ring-2 ring-indigo-500/20">
                                        <textarea ref={evidenceTextareaRef} className="flex-1 w-full h-full p-6 bg-transparent resize-none focus:outline-none text-slate-700 dark:text-slate-300 font-mono text-sm leading-relaxed" placeholder="Paste audit evidence here..." value={evidence} onChange={(e) => setEvidence(e.target.value)} onPaste={handlePaste}/>
                                        <div className="absolute bottom-4 right-4 flex gap-2">
                                            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" multiple onChange={(e) => e.target.files && setPastedImages(prev => [...prev, ...Array.from(e.target.files!)])} />
                                            <button onClick={() => fileInputRef.current?.click()} className="p-3 rounded-xl bg-gray-100 dark:bg-slate-800 hover:bg-indigo-50 text-slate-600 hover:text-indigo-600 transition-all hover:scale-110"><Icon name="Demo8_GridPlus" size={20}/></button>
                                        </div>
                                    </div>
                                    {pastedImages.length > 0 && <div className="flex-shrink-0 p-3 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-2xl animate-in slide-in-from-bottom-5">
                                        <div className="flex justify-between items-center mb-2 px-1"><h4 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Pending Extraction ({pastedImages.length})</h4><button onClick={() => setPastedImages([])} className="text-xs text-red-500 font-bold">Clear All</button></div>
                                        <div className="flex gap-3 overflow-x-auto custom-scrollbar pb-2">
                                            {pastedImages.map((file, idx) => (<div key={idx} className="relative group flex-shrink-0 w-24 h-24 bg-white dark:bg-slate-800 rounded-xl overflow-hidden"><img src={URL.createObjectURL(file)} className="w-full h-full object-cover"/><div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center"><button onClick={() => setPastedImages(prev => prev.filter((_, i) => i !== idx))} className="bg-red-500 text-white rounded-full p-1"><Icon name="X" size={14}/></button></div></div>))}
                                            <div className="flex-shrink-0 w-24 h-24 flex items-center justify-center"><button onClick={handleOcrUpload} disabled={isOcrLoading} className="w-full h-full bg-indigo-600 text-white rounded-xl flex flex-col items-center justify-center gap-2 hover:scale-105 transition-all">{isOcrLoading ? <Icon name="Loader" className="animate-spin" size={24}/> : <Icon name="ScanText" size={24}/>}<span className="text-[10px] font-bold">Extract</span></button></div>
                                        </div>
                                    </div>}
                                </div>
                                <div className="flex items-center justify-center md:justify-end gap-2 w-full">
                                    <button onClick={handleAnalyze} disabled={!isReadyForAnalysis} title={getAnalyzeTooltip()} className={`h-10 px-4 rounded-xl font-bold flex items-center gap-3 ${isReadyForAnalysis ? "btn-shrimp shadow-xl active:scale-95" : "bg-gray-200 dark:bg-slate-800 opacity-70 cursor-not-allowed"}`}>{isAnalyzeLoading ? <SparkleLoader className="text-white"/> : <Icon name="Wand2" size={18}/>}<span className="hidden md:inline text-xs uppercase tracking-wider">Analyze Compliance</span></button>
                                    <button onClick={() => smartExport.startSmartExport(evidence, 'evidence', evidenceLanguage)} className="h-10 px-4 bg-white dark:bg-slate-800 border hover:border-indigo-500 rounded-xl text-xs font-bold flex items-center gap-2 transition-all"><Icon name="Download"/> <span className="hidden md:inline">Export Raw</span><div className="lang-pill-container ml-1"><span onClick={(e) => {e.stopPropagation(); setEvidenceLanguage('en');}} className={`lang-pill-btn ${evidenceLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span><span onClick={(e) => {e.stopPropagation(); setEvidenceLanguage('vi');}} className={`lang-pill-btn ${evidenceLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span></div></button>
                                </div>
                            </div>
                        )}

                        {layoutMode === 'findings' && (
                             <div className="h-full flex flex-col animate-fade-in-up">
                                <div ref={findingsContainerRef} className="flex-1 overflow-y-auto custom-scrollbar space-y-4 pr-2 pb-4">
                                    {(!analysisResult || analysisResult.length === 0) && !isAnalyzeLoading && <div className="h-full flex flex-col items-center justify-center text-slate-400 opacity-60"><Icon name="Wand2" size={64} className="mb-4"/><p>No analysis data yet.</p></div>}
                                    {findingsViewMode === 'matrix' && analysisResult && <div className="grid grid-cols-4 sm:grid-cols-6 md:grid-cols-10 gap-2 p-1">{analysisResult.map((result, idx) => { const isActive = selectedFindings[result.clauseId]; let bgColor = isActive ? (result.status === 'COMPLIANT' ? 'bg-emerald-500' : result.status === 'NC_MAJOR' ? 'bg-red-600' : result.status === 'NC_MINOR' ? 'bg-orange-500' : 'bg-blue-500') : 'bg-gray-200 dark:bg-slate-700'; return (<div key={result.clauseId} className={`aspect-square rounded-lg flex items-center justify-center text-[10px] font-bold cursor-pointer hover:scale-110 shadow-sm ${bgColor} ${isActive ? 'text-white' : 'text-slate-500 opacity-50'}`} onClick={() => setSelectedFindings(prev => ({...prev, [result.clauseId]: !prev[result.clauseId]}))}>{result.clauseId}</div>); })}</div>}
                                    {findingsViewMode === 'list' && analysisResult?.map((result, idx) => (
                                        <div key={result.clauseId} className={`p-5 rounded-2xl bg-white dark:bg-slate-900 border-l-4 shadow-sm transition-all ${!selectedFindings[result.clauseId] ? 'opacity-60 grayscale' : result.status === 'COMPLIANT' ? 'border-emerald-500' : result.status === 'NC_MAJOR' ? 'border-red-600' : result.status === 'NC_MINOR' ? 'border-orange-500' : 'border-blue-500'}`}>
                                            <div className="flex justify-between items-start gap-4">
                                                <div className="flex-1">
                                                    <div className="flex items-center gap-3 mb-2"><input type="checkbox" checked={!!selectedFindings[result.clauseId]} onChange={() => setSelectedFindings(prev => ({...prev, [result.clauseId]: !prev[result.clauseId]}))} className="w-5 h-5 rounded text-indigo-600"/><span className="font-black text-sm bg-gray-100 dark:bg-slate-800 px-2 py-0.5 rounded">{result.clauseId}</span><select value={result.status} onChange={(e) => handleUpdateFinding(idx, 'status', e.target.value as FindingStatus)} className={`text-xs font-bold px-2 py-0.5 rounded uppercase border-none outline-none cursor-pointer ${result.status === 'COMPLIANT' ? 'bg-emerald-100 text-emerald-700' : result.status === 'NC_MAJOR' ? 'bg-red-100 text-red-700' : result.status === 'NC_MINOR' ? 'bg-orange-100 text-orange-800' : 'bg-blue-100 text-blue-700'}`}><option value="COMPLIANT">COMPLIANT</option><option value="OFI">OFI</option><option value="NC_MINOR">NC MINOR</option><option value="NC_MAJOR">NC MAJOR</option></select></div>
                                                    <input className="w-full text-sm font-bold mb-1 bg-transparent border-b border-transparent hover:border-gray-200 focus:border-indigo-500 outline-none" value={result.reason} onChange={(e) => handleUpdateFinding(idx, 'reason', e.target.value)}/>
                                                    <div className="bg-gray-50 dark:bg-slate-950/50 p-2 rounded-lg border border-gray-100 mt-1"><textarea className="w-full text-xs text-slate-500 italic bg-transparent border-none resize-y min-h-[40px]" value={result.evidence} onChange={(e) => handleUpdateFinding(idx, 'evidence', e.target.value)}/></div>
                                                    {result.suggestion && <div className="mt-2 flex gap-2"><Icon name="Lightbulb" size={14} className="text-amber-500"/><p className="text-xs text-slate-600">{result.suggestion}</p></div>}
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                    {isAnalyzeLoading && <div className="p-5 rounded-2xl bg-white dark:bg-slate-900 border border-indigo-100 shadow-lg animate-pulse"><div className="flex items-center gap-3"><Icon name="Loader" size={20} className="animate-spin text-indigo-600"/><p className="text-sm font-bold">{loadingMessage}</p></div></div>}
                                </div>
                                <div className="flex items-center justify-center md:justify-end gap-2 w-full mt-2">
                                    <div className="h-10 bg-gray-100 dark:bg-slate-800 p-1 rounded-xl flex items-center"><button onClick={() => setFindingsViewMode('list')} className={`h-full px-3 rounded-lg flex items-center gap-2 text-xs font-bold ${findingsViewMode === 'list' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}><Icon name="LayoutList" size={16}/> List</button><button onClick={() => setFindingsViewMode('matrix')} className={`h-full px-3 rounded-lg flex items-center gap-2 text-xs font-bold ${findingsViewMode === 'matrix' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}><Icon name="Grid" size={16}/> Matrix</button></div>
                                    <button onClick={() => { const reportTxt = analysisResult?.filter(r => selectedFindings[r.clauseId]).map(r => `[${r.status}] Clause ${r.clauseId}: ${r.conclusion_report}`).join('\n\n') || ""; smartExport.startSmartExport(reportTxt, 'notes', notesLanguage); }} disabled={!analysisResult || analysisResult.length === 0} className="h-10 px-4 bg-white dark:bg-slate-800 border hover:border-indigo-500 rounded-xl text-xs font-bold flex items-center gap-2"><Icon name="Download"/> Download Findings <div className="lang-pill-container ml-2"><span onClick={(e) => {e.stopPropagation(); setNotesLanguage('en');}} className={`lang-pill-btn ${notesLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span><span onClick={(e) => {e.stopPropagation(); setNotesLanguage('vi');}} className={`lang-pill-btn ${notesLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span></div></button>
                                </div>
                            </div>
                        )}

                        {layoutMode === 'report' && (
                             <div className="h-full flex flex-col animate-fade-in-up">
                                <div className="flex-1 bg-white dark:bg-slate-900 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm p-6 overflow-hidden flex flex-col relative">
                                    <div className="flex items-center justify-between mb-4 pb-2 border-b border-gray-50 dark:border-slate-800"><h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Preview</h4>{reportTemplate ? <div className="flex items-center gap-2 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-700 px-3 py-1.5 rounded-lg"><Icon name="FileEdit" size={14}/><span className="text-xs font-bold">Template: {templateFileName.substring(0, 15)}...</span></div> : <div className="flex items-center gap-2 text-slate-400 bg-gray-50 px-3 py-1.5 rounded-lg"><Icon name="FileText" size={14}/><span className="text-xs font-medium">Standard ISO Structure</span></div>}</div>
                                    {!finalReportText ? <div className="flex-1 flex flex-col items-center justify-center text-center p-8"><Icon name="FileText" size={40} className="text-indigo-200 mb-6"/><h4 className="text-lg font-bold">Ready to Synthesize</h4><p className="text-sm text-slate-500 max-w-md">Generate comprehensive report.</p></div> : <textarea className="flex-1 w-full h-full bg-transparent resize-none focus:outline-none text-slate-800 dark:text-slate-200 font-mono text-sm leading-relaxed" value={finalReportText} onChange={(e) => setFinalReportText(e.target.value)}/>}
                                </div>
                                <div className="flex items-center justify-center md:justify-end gap-2 w-full mt-2">
                                    <div className="relative"><input type="file" id="template-upload" className="hidden" accept=".txt,.md,.docx" onChange={handleTemplateUpload}/><label htmlFor="template-upload" className={`cursor-pointer h-10 px-4 rounded-xl text-xs font-bold flex items-center gap-2 border shadow-sm ${reportTemplate ? 'bg-indigo-50 text-indigo-600 border-indigo-200' : 'bg-gray-100 text-slate-600'}`}><Icon name="UploadCloud" size={14}/> {templateFileName ? "Change Template" : "Upload Template"}</label></div>
                                    <button onClick={handleGenerateReport} disabled={!analysisResult || analysisResult.length === 0} className="h-10 px-4 bg-gradient-to-r from-indigo-600 to-purple-600 text-white rounded-xl font-bold text-xs shadow-xl flex items-center gap-3">{isReportLoading ? <SparkleLoader className="text-white"/> : <Icon name="Wand2" size={18}/>} Generate Final Report</button>
                                    <button onClick={() => smartExport.startSmartExport(finalReportText || "", 'report', exportLanguage)} disabled={!finalReportText} className="h-10 px-4 bg-white dark:bg-slate-800 border hover:border-indigo-500 rounded-xl text-xs font-bold flex items-center gap-2"><Icon name="Download"/> Export <div className="lang-pill-container ml-2"><span onClick={(e) => {e.stopPropagation(); setExportLanguage('en');}} className={`lang-pill-btn ${exportLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span><span onClick={(e) => {e.stopPropagation(); setExportLanguage('vi');}} className={`lang-pill-btn ${exportLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span></div></button>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* MODALS */}
            <CommandPaletteModal isOpen={isCmdPaletteOpen} onClose={() => setIsCmdPaletteOpen(false)} actions={commandActions} onSelectAction={(item: any) => { item.action(); setIsCmdPaletteOpen(false); }}/>
            <ReleaseNotesModal isOpen={showAboutModal} onClose={() => setShowAboutModal(false)} />

            <Modal isOpen={showSettingsModal} title="Settings & API Keys" onClose={() => setShowSettingsModal(false)}>
                <div className="space-y-6">
                    <div>
                        <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-3">Manage API Keys</h4>
                        <div className="space-y-3">
                            {gemini.apiKeys.map(profile => (
                                <div key={profile.id} className={`p-3 rounded-xl border flex items-center justify-between ${profile.id === gemini.activeKeyId ? 'bg-indigo-50 border-indigo-200' : 'bg-white border-gray-100 dark:bg-slate-800 dark:border-slate-700'}`}>
                                    <div className="flex items-center gap-3 overflow-hidden"><div onClick={() => gemini.setActiveKeyId(profile.id)} className={`cursor-pointer w-4 h-4 rounded-full border-2 flex items-center justify-center ${profile.id === gemini.activeKeyId ? 'border-indigo-500' : 'border-gray-300'}`}>{profile.id === gemini.activeKeyId && <div className="w-2 h-2 rounded-full bg-indigo-500"></div>}</div><div className="flex flex-col min-w-0"><div className="flex items-center gap-2"><span className="text-sm font-bold truncate">{profile.label}</span>{profile.status === 'valid' && <span className="text-[9px] bg-emerald-100 text-emerald-700 px-1.5 rounded font-bold">Valid</span>}{profile.status === 'invalid' && <span className="text-[9px] bg-red-100 text-red-700 px-1.5 rounded font-bold">Invalid</span>}{profile.status === 'quota_exceeded' && <span className="text-[9px] bg-orange-100 text-orange-700 px-1.5 rounded font-bold">Quota</span>}{profile.status === 'checking' && <Icon name="Loader" size={10} className="animate-spin text-indigo-500"/>}</div><div className="flex items-center gap-2"><span className="text-[10px] text-slate-400 font-mono truncate">{profile.key.substring(0, 8)}...</span>{profile.activeModel && <span className="text-[9px] font-mono bg-blue-50 text-blue-600 px-1.5 rounded">{profile.activeModel.replace('gemini-', '')}</span>}</div></div></div>
                                    <div className="flex items-center gap-1"><button onClick={() => gemini.handleRefreshStatus(profile.id)} className="p-2 text-slate-400 hover:text-indigo-500"><Icon name="RefreshCw" size={14} className={profile.status === 'checking' ? 'animate-spin' : ''}/></button><button onClick={() => gemini.handleDeleteKey(profile.id)} className="p-2 text-slate-400 hover:text-red-500"><Icon name="Trash2" size={14}/></button></div>
                                </div>
                            ))}
                            <div className="p-3 bg-gray-50 dark:bg-slate-800/50 rounded-xl border border-dashed border-gray-300 flex flex-col gap-3">
                                <input className="w-full bg-transparent text-xs outline-none border-b border-gray-200 pb-2" placeholder="Enter API Key" value={newKeyInput} onChange={(e) => setNewKeyInput(e.target.value)}/>
                                <div className="flex gap-2"><input className="flex-1 bg-transparent text-xs outline-none border-b border-gray-200 pb-2" placeholder="Label" value={newKeyLabel} onChange={(e) => setNewKeyLabel(e.target.value)}/><button onClick={() => { gemini.handleAddKey(newKeyInput, newKeyLabel); setNewKeyInput(""); setNewKeyLabel(""); }} disabled={!newKeyInput || gemini.isCheckingKey} className="px-4 py-1.5 bg-indigo-600 text-white text-xs font-bold rounded-lg">{gemini.isCheckingKey ? <Icon name="Loader" className="animate-spin"/> : "Add"}</button></div>
                            </div>
                        </div>
                    </div>
                </div>
            </Modal>

            {smartExport.exportState.isOpen && (
                <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
                    <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-3xl shadow-2xl border border-gray-100 dark:border-slate-800 p-6">
                        <div className="flex justify-between items-start mb-4"><div><h3 className="text-lg font-black flex items-center gap-2"><Icon name="Download" className="text-indigo-500"/> Export Manager</h3><p className="text-xs text-slate-500">Refining to {smartExport.exportState.targetLang === 'vi' ? 'Vietnamese' : 'English'}</p></div>{!smartExport.exportState.isPaused && !smartExport.exportState.isFinished && <span className="text-xs font-mono bg-indigo-100 text-indigo-600 px-2 py-1 rounded animate-pulse">Processing...</span>}</div>
                        <div className="mb-2 flex justify-between text-xs font-bold"><span>Progress</span><span>{Math.round((smartExport.exportState.processedChunksCount / smartExport.exportState.totalChunks) * 100)}%</span></div>
                        <div className="w-full h-3 bg-gray-100 dark:bg-slate-800 rounded-full overflow-hidden mb-6 relative"><div className={`h-full transition-all duration-500 ease-out ${smartExport.exportState.error ? 'bg-red-500' : smartExport.exportState.isFinished ? 'bg-emerald-500' : 'bg-indigo-500'}`} style={{ width: `${(smartExport.exportState.processedChunksCount / smartExport.exportState.totalChunks) * 100}%` }}><div className="absolute inset-0 bg-white/20 animate-[shimmer_2s_infinite]"></div></div></div>
                        <div className="bg-gray-50 dark:bg-slate-950/50 p-4 rounded-xl mb-6 min-h-[100px] flex flex-col justify-center items-center text-center">
                            {smartExport.exportState.isFinished ? <div className="text-emerald-500 flex flex-col items-center gap-2"><Icon name="CheckCircle2" size={32}/><span className="font-bold">Export Complete!</span><span className="text-xs text-slate-500">Downloading...</span></div> : smartExport.exportState.error ? <div className="text-red-500 flex flex-col items-center gap-2 w-full"><Icon name="AlertCircle" size={32}/><span className="font-bold">Export Paused</span><span className="text-xs text-slate-500 mb-2">{smartExport.exportState.error}</span><div className="w-full mt-2"><input type="text" className="w-full bg-white dark:bg-slate-900 border border-red-200 rounded-lg px-3 py-2 text-xs" placeholder="Paste Rescue Key..." value={smartExport.rescueKey} onChange={(e) => smartExport.setRescueKey(e.target.value)}/></div></div> : <div className="flex flex-col items-center gap-2"><p className="text-xs text-slate-500">Processing Chunk</p><p className="text-2xl font-black text-indigo-600">{smartExport.exportState.processedChunksCount + 1} <span className="text-base text-slate-400 font-normal">/ {smartExport.exportState.totalChunks}</span></p></div>}
                        </div>
                        <div className="flex gap-3">{smartExport.exportState.isPaused ? <><button onClick={() => setShowSettingsModal(true)} className="flex-1 py-3 bg-gray-100 hover:bg-gray-200 rounded-xl font-bold text-xs">Manage Keys</button><button onClick={smartExport.handleResumeExport} disabled={smartExport.isRescuing} className={`flex-1 py-3 text-white rounded-xl font-bold text-xs shadow-lg flex items-center justify-center gap-2 ${smartExport.rescueKey ? 'bg-emerald-500 hover:bg-emerald-600' : 'bg-indigo-600 hover:bg-indigo-700'}`}>{smartExport.isRescuing ? <Icon name="Loader" className="animate-spin" size={14}/> : null}{smartExport.rescueKey ? "Add Key & Resume" : "Resume Export"}</button></> : <button onClick={() => smartExport.setExportState(prev => ({ ...prev, isOpen: false, isPaused: true }))} className="w-full py-3 bg-gray-100 hover:bg-gray-200 text-slate-500 rounded-xl font-bold text-xs">{smartExport.exportState.isFinished ? "Close" : "Cancel"}</button>}</div>
                    </div>
                </div>
            )}
            {isReportLoading && <AINeuralLoader message="Synthesizing Audit Report..." />}
        </div>
    );
}

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { APP_VERSION, STANDARDS_DATA, INITIAL_EVIDENCE, MODEL_HIERARCHY } from './constants';
import { StandardsData, AuditInfo, AnalysisResult, Standard, ApiKeyProfile, Clause, FindingsViewMode, FindingStatus } from './types';
import { Icon, FontSizeController, SparkleLoader, Modal, AINeuralLoader, Toast, CommandPaletteModal } from './components/UI';
import Sidebar from './components/Sidebar';
import ReleaseNotesModal from './components/ReleaseNotesModal';
import { generateOcrContent, generateAnalysis, generateTextReport, validateApiKey } from './services/geminiService';
import { cleanAndParseJSON, fileToBase64, cleanFileName } from './utils';

declare var mammoth: any;

type LayoutMode = 'evidence' | 'findings' | 'report' | 'split';
type ExportLanguage = 'en' | 'vi';

// --- Smart Export State Interface ---
interface ExportState {
    isOpen: boolean;
    isPaused: boolean;
    isFinished: boolean;
    totalChunks: number;
    processedChunksCount: number;
    chunks: string[];
    results: string[];
    error: string | null;
    currentType: 'notes' | 'report' | 'evidence';
    targetLang: ExportLanguage;
}

function App() {
    // -- STATE --
    const [fontSizeScale, setFontSizeScale] = useState(1.0);
    const [isDarkMode, setIsDarkMode] = useState(true);
    const [sidebarWidth, setSidebarWidth] = useState(390);
    const [isSidebarOpen, setIsSidebarOpen] = useState(true);
    const [showAboutModal, setShowAboutModal] = useState(false);
    const [showSettingsModal, setShowSettingsModal] = useState(false);

    // Feature: Command Palette
    const [isCmdPaletteOpen, setIsCmdPaletteOpen] = useState(false);

    // Feature: Matrix View
    const [findingsViewMode, setFindingsViewMode] = useState<FindingsViewMode>('list');

    // API Key Management State
    const [apiKeys, setApiKeys] = useState<ApiKeyProfile[]>([]);
    const [activeKeyId, setActiveKeyId] = useState<string>("");
    const [newKeyInput, setNewKeyInput] = useState("");
    const [newKeyLabel, setNewKeyLabel] = useState("");
    const [isCheckingKey, setIsCheckingKey] = useState(false);

    // Toast State
    const [toastMsg, setToastMsg] = useState<string | null>(null);

    const [exportLanguage, setExportLanguage] = useState<ExportLanguage>('en');
    const [notesLanguage, setNotesLanguage] = useState<ExportLanguage>('vi'); 
    const [evidenceLanguage, setEvidenceLanguage] = useState<ExportLanguage>('en'); 
    const [isDragging, setIsDragging] = useState(false);

    const [reportTemplate, setReportTemplate] = useState<string>("");
    const [templateFileName, setTemplateFileName] = useState<string>("");

    const [customStandards, setCustomStandards] = useState<StandardsData>(STANDARDS_DATA);
    const [standardKey, setStandardKey] = useState<string>("ISO 9001:2015");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>({ company: "", smo: "", department: "", interviewee: "", auditor: "", type: "" });
    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [pastedImages, setPastedImages] = useState<File[]>([]);

    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [finalReportText, setFinalReportText] = useState<string | null>(null);
    const [layoutMode, setLayoutMode] = useState('evidence' as LayoutMode);

    // Loading States
    const [isOcrLoading, setIsOcrLoading] = useState(false);
    const [isAnalyzeLoading, setIsAnalyzeLoading] = useState(false);
    const [currentAnalyzingClause, setCurrentAnalyzingClause] = useState<string>(""); 
    const [loadingMessage, setLoadingMessage] = useState<string>(""); 
    const [isReportLoading, setIsReportLoading] = useState(false);

    // Smart Export State
    const [exportState, setExportState] = useState<ExportState>({
        isOpen: false,
        isPaused: false,
        isFinished: false,
        totalChunks: 0,
        processedChunksCount: 0,
        chunks: [],
        results: [],
        error: null,
        currentType: 'report',
        targetLang: 'en'
    });

    const [aiError, setAiError] = useState<string | null>(null);

    // Rescue Key State (Inline Input)
    const [rescueKey, setRescueKey] = useState("");
    const [isRescuing, setIsRescuing] = useState(false);

    // Logo Animation State
    const [logoKey, setLogoKey] = useState(0);

    // Fluid Tab State
    const [tabStyle, setTabStyle] = useState({ left: 0, width: 0, opacity: 0, color: '' });
    const tabsRef = useRef<(HTMLButtonElement | null)[]>([]);
    const tabsContainerRef = useRef<HTMLDivElement>(null); 

    // Process Steps Configuration
    const tabsList = [
        { id: 'evidence', label: '1. Evidence', icon: 'ScanText', colorClass: 'bg-blue-500', textClass: 'text-blue-600', borderClass: 'border-blue-500', bgSoft: 'bg-blue-50 dark:bg-blue-900/10' }, 
        { id: 'findings', label: '2. Findings', icon: 'Wand2', colorClass: 'bg-purple-500', textClass: 'text-purple-600', borderClass: 'border-purple-500', bgSoft: 'bg-purple-50 dark:bg-purple-900/10' }, 
        { id: 'report', label: '3. Report', icon: 'FileText', colorClass: 'bg-emerald-500', textClass: 'text-emerald-600', borderClass: 'border-emerald-500', bgSoft: 'bg-emerald-50 dark:bg-emerald-900/10' }
    ];

    const currentTabConfig = tabsList.find(t => t.id === layoutMode) || tabsList[0];

    const fileInputRef = useRef<HTMLInputElement>(null);
    const evidenceTextareaRef = useRef<HTMLTextAreaElement>(null);
    const findingsContainerRef = useRef<HTMLDivElement>(null);

    const allStandards = { ...STANDARDS_DATA, ...customStandards };
    const hasEvidence = evidence.trim().length > 0 || pastedImages.length > 0;

    const isReadyForAnalysis = !isAnalyzeLoading && selectedClauses.length > 0 && hasEvidence;

    // --- HELPER: INSERT TEXT AT CURSOR ---
    const insertTextAtCursor = (textToInsert: string) => {
        if (evidenceTextareaRef.current) {
            const textarea = evidenceTextareaRef.current;
            const start = textarea.selectionStart;
            const end = textarea.selectionEnd;
            const newValue = evidence.substring(0, start) + textToInsert + evidence.substring(end);

            setEvidence(newValue);

            if (layoutMode !== 'evidence') setLayoutMode('evidence');

            setTimeout(() => {
                if (evidenceTextareaRef.current) {
                    evidenceTextareaRef.current.focus();
                    evidenceTextareaRef.current.setSelectionRange(start + textToInsert.length, start + textToInsert.length);
                }
            }, 100);
        } else {
            setEvidence(prev => prev + "\n" + textToInsert);
            if (layoutMode !== 'evidence') setLayoutMode('evidence');
        }
    };

    // --- EFFECTS & PERSISTENCE ---
    useEffect(() => {
        const storedScale = localStorage.getItem('iso_font_scale');
        if (storedScale) setFontSizeScale(parseFloat(storedScale));

        loadSessionData();
        const loadedKeys = loadKeyData();

        if (!hasStartupChecked.current && loadedKeys.length > 0) {
            hasStartupChecked.current = true;
            checkAllKeys(loadedKeys);
        }

        const savedDarkMode = localStorage.getItem('iso_dark_mode');
        if (savedDarkMode !== null) {
            setIsDarkMode(savedDarkMode === 'true');
        } else {
            setIsDarkMode(true); 
        }

        if (window.innerWidth < 768) {
            setIsSidebarOpen(false);
        }
    }, []);

    const hasStartupChecked = useRef(false);

    useEffect(() => {
        const updateTabs = () => {
            const activeIndex = tabsList.findIndex(t => t.id === layoutMode);
            const el = tabsRef.current[activeIndex];
            if (el) {
                setTabStyle({
                    left: el.offsetLeft,
                    width: el.offsetWidth,
                    opacity: 1,
                    color: tabsList[activeIndex].colorClass
                });
            }
        };
        updateTabs();
        const t = setTimeout(updateTabs, 50);
        const observer = new ResizeObserver(() => {
            updateTabs();
        });
        if (tabsContainerRef.current) observer.observe(tabsContainerRef.current);
        return () => {
            clearTimeout(t);
            observer.disconnect();
        };
    }, [layoutMode, sidebarWidth, fontSizeScale]); 

    useEffect(() => {
        if (layoutMode === 'findings' && findingsContainerRef.current) {
            findingsContainerRef.current.scrollTop = findingsContainerRef.current.scrollHeight;
        }
    }, [analysisResult]);

    // NEW: Trigger export processor when not paused and not finished
    useEffect(() => {
        if (exportState.isOpen && !exportState.isPaused && !exportState.isFinished && exportState.processedChunksCount < exportState.totalChunks) {
            processNextExportChunk();
        } else if (exportState.isOpen && exportState.processedChunksCount >= exportState.totalChunks && !exportState.isFinished) {
            finishExport();
