export const INITIAL_EVIDENCE = "";

import React, { useState } from 'react';
import Sidebar from './components/Sidebar';
import ReleaseNotesModal from './components/ReleaseNotesModal';
import { 
    Icon, SparkleLoader, Toast, AINeuralLoader, FontSizeController, 
    SnowOverlay 
} from './components/UI';
import { 
    StandardsData, AuditInfo, AnalysisResult, Standard 
} from './types';
import { 
    STANDARDS_DATA, INITIAL_EVIDENCE 
} from './constants';
import { 
    generateAnalysis 
} from './services/geminiService';
import { 
    cleanAndParseJSON 
} from './utils';

const App = () => {
    // --- State ---
    const [sidebarOpen, setSidebarOpen] = useState(true);
    const [sidebarWidth, setSidebarWidth] = useState(360);
    const [fontSizeScale, setFontSizeScale] = useState(1.0);

    // Data State
    const [standards, setStandards] = useState<StandardsData>(STANDARDS_DATA);
    const [standardKey, setStandardKey] = useState<string>(Object.keys(STANDARDS_DATA)[0] || "ISO 9001:2015");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>({
        company: "", smo: "", department: "", interviewee: "", auditor: "", type: "Internal"
    });
    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);

    // Evidence State
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [evidenceLanguage, setEvidenceLanguage] = useState<'en' | 'vi'>('en');

    // Analysis State
    const [isAnalyzeLoading, setIsAnalyzeLoading] = useState(false);
    const [analysisResults, setAnalysisResults] = useState<AnalysisResult[]>([]);
    const [loadingMessage, setLoadingMessage] = useState("");

    // UI State
    const [showReleaseNotes, setShowReleaseNotes] = useState(false);
    const [toastMessage, setToastMessage] = useState("");

    // --- Logic ---

    const handleAnalyze = async () => {
        if (!evidence || !evidence.trim() || selectedClauses.length === 0) return;

        setIsAnalyzeLoading(true);
        setLoadingMessage("Analyzing Compliance...");

        try {
            // Find selected clauses objects
            const currentStd = standards[standardKey];
            const allClauses = currentStd.groups.flatMap(g => g.clauses);
            const flatten = (list: any[]): any[] => list.reduce((acc, c) => {
                acc.push(c);
                if(c.subClauses) acc.push(...flatten(c.subClauses));
                return acc;
            }, []);
            const flatList = flatten(allClauses);
            const targets = flatList.filter(c => selectedClauses.includes(c.id));

            // Construct Prompt
            const clauseText = targets.map(c => `${c.code} ${c.title}: ${c.description}`).join('\n');
            const prompt = `
            Analyze the following evidence against these ISO clauses:

            CLAUSES:
            ${clauseText}

            EVIDENCE:
            ${evidence}

            Provide compliance status, reason, suggestion, and evidence excerpt for each clause.
            Result must be a JSON array.
            `;

            const systemInstruction = `You are an expert ISO auditor for ${currentStd.name}. Language: ${evidenceLanguage === 'vi' ? 'Vietnamese' : 'English'}.`;

            const resultJson = await generateAnalysis(prompt, systemInstruction);
            const results = cleanAndParseJSON(resultJson);

            if (results && Array.isArray(results)) {
                setAnalysisResults(results);
                setToastMessage("Analysis Complete");
            } else {
                setToastMessage("Analysis failed to parse");
            }

        } catch (e) {
            console.error(e);
            setToastMessage("Analysis Error");
        } finally {
            setIsAnalyzeLoading(false);
            setLoadingMessage("");
        }
    };

    const isReadyForAnalysis = evidence && evidence.trim().length > 0 && selectedClauses.length > 0;

    const getAnalyzeTooltip = () => {
        if (!evidence || !evidence.trim()) return "Please enter evidence first";
        if (selectedClauses.length === 0) return "Select clauses to audit";
        return "Start AI Analysis";
    };

    const startSmartExport = (content: string, type: string, lang: string) => {
        const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
        const filename = `audit-${type}-${lang}-${timestamp}.txt`;
        const element = document.createElement("a");
        const file = new Blob([content], { type: 'text/plain' });
        element.href = URL.createObjectURL(file);
        element.download = filename;
        document.body.appendChild(element);
        element.click();
        document.body.removeChild(element);
        setToastMessage("Export started...");
    };

    const adjustFontSize = (direction: 'increase' | 'decrease') => {
        setFontSizeScale(prev => direction === 'increase' ? Math.min(prev + 0.1, 1.5) : Math.max(prev - 0.1, 0.8));
    };

    const onAddNewStandard = () => {
        const name = prompt("Enter Standard Name:");
        if (name) {
            setStandards(prev => ({
                ...prev,
                [name]: { name, description: "Custom Standard", groups: [] }
            }));
            setStandardKey(name);
        }
    };

    const onUpdateStandard = (std: Standard) => {
        setStandards(prev => ({ ...prev, [standardKey]: std }));
    };

    const onResetStandard = (key: string) => {
         if (STANDARDS_DATA[key]) {
             setStandards(prev => ({...prev, [key]: STANDARDS_DATA[key]}));
        }
    };

    return (
        <div className="flex h-screen w-screen overflow-hidden bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-slate-100 font-sans transition-all duration-300" style={{ fontSize: `${fontSizeScale}rem` }}>

           <Sidebar 
               isOpen={sidebarOpen}
               width={sidebarWidth}
               setWidth={setSidebarWidth}
               standards={standards}
               standardKey={standardKey}
               setStandardKey={setStandardKey}
               auditInfo={auditInfo}
               setAuditInfo={setAuditInfo}
               selectedClauses={selectedClauses}
               setSelectedClauses={setSelectedClauses}
               onAddNewStandard={onAddNewStandard}
               onUpdateStandard={onUpdateStandard}
               onResetStandard={onResetStandard}
           />

           <div className="flex-1 flex flex-col min-w-0 relative">
                {/* Header Toggle for Sidebar if closed */}
                {!sidebarOpen && (
                    <button onClick={() => setSidebarOpen(true)} className="absolute left-4 top-4 z-50 p-2 bg-white dark:bg-slate-800 rounded-lg shadow-md border border-gray-200 dark:border-slate-700">
                        <Icon name="LayoutList" />
                    </button>
                )}

                <main className="flex-1 overflow-hidden flex flex-col md:flex-row relative">
                    {/* Input Section */}
                    <div className="flex-1 flex flex-col border-r border-gray-200 dark:border-slate-800 min-w-0">
                         <div className="flex-1 relative">
                            <textarea 
                                value={evidence}
                                onChange={(e) => setEvidence(e.target.value)}
                                className="w-full h-full p-6 bg-transparent outline-none resize-none text-sm leading-relaxed custom-scrollbar"
                                placeholder="Paste your audit evidence here (interview notes, observation logs, document content)..."
                            />
                             <div className="absolute top-4 right-4 flex gap-2">
                                <FontSizeController fontSizeScale={fontSizeScale} adjustFontSize={adjustFontSize} />
                                <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-2 bg-gray-100 dark:bg-slate-800 rounded-lg text-slate-500 hover:text-indigo-600 transition-colors">
                                    <Icon name={sidebarOpen ? "CollapsePanel" : "ExpandPanel"} size={18}/>
                                </button>
                             </div>
                         </div>

                        {/* Footer - Analysis Controls */}
                        <div className="p-4 border-t border-gray-200 dark:border-slate-800 bg-white dark:bg-slate-900 z-10">
                             {/* BLOCK 1 FOOTER: Analysis, Report (Export) */}
                                <div className="flex items-center justify-center md:justify-end gap-2 md:gap-3 w-full">
                                    <button onClick={handleAnalyze} disabled={!isReadyForAnalysis} title={getAnalyzeTooltip()} className={`h-9 md:h-10 w-auto px-3 md:px-4 rounded-xl font-bold transition-all duration-300 flex items-center justify-center gap-2 md:gap-3 ${isReadyForAnalysis ? "shadow-xl active:scale-95 bg-indigo-600 text-white hover:bg-indigo-700" : "bg-gray-200 dark:bg-slate-800 text-slate-400 dark:text-slate-600 opacity-70 cursor-not-allowed border border-transparent"}`}>
                                        {isAnalyzeLoading ? <SparkleLoader className="text-white"/> : <Icon name="Wand2" size={18}/>}
                                        <span className="hidden md:inline text-xs uppercase tracking-wider">Analyze Compliance</span>
                                    </button>

                                    <button 
                                        onClick={() => startSmartExport(evidence, 'evidence', evidenceLanguage)} 
                                        disabled={!evidence || !evidence.trim()} 
                                        className="h-9 md:h-10 w-auto px-3 md:px-4 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm disabled:opacity-50 disabled:cursor-not-allowed disabled:active:scale-100 disabled:hover:border-gray-200 dark:disabled:hover:border-slate-700" 
                                        title="Export Raw Text"
                                    >
                                        <Icon name="Download"/> 
                                        <span className="hidden md:inline">Export Raw</span>
                                        <div className="flex items-center gap-1 ml-1">
                                            <span onClick={(e) => {e.stopPropagation(); setEvidenceLanguage('en');}} className={`cursor-pointer px-1.5 py-0.5 rounded text-[10px] ${evidenceLanguage === 'en' ? 'bg-indigo-100 text-indigo-700 font-bold' : 'text-slate-400 hover:text-slate-600'}`}>EN</span>
                                            <span onClick={(e) => {e.stopPropagation(); setEvidenceLanguage('vi');}} className={`cursor-pointer px-1.5 py-0.5 rounded text-[10px] ${evidenceLanguage === 'vi' ? 'bg-indigo-100 text-indigo-700 font-bold' : 'text-slate-400 hover:text-slate-600'}`}>VI</span>
                                        </div>
                                    </button>
                                </div>
                        </div>
                    </div>

                    {/* Results / Right Panel */}
                    <div className="flex-1 bg-gray-50 dark:bg-slate-950 p-6 overflow-y-auto custom-scrollbar min-w-0">
                         {analysisResults.length === 0 ? (
                             <div className="h-full flex flex-col items-center justify-center text-slate-400 opacity-60">
                                 <Icon name="TDSolidLink" size={64} className="mb-4 grayscale opacity-20"/>
                                 <p className="text-sm font-medium">Ready to analyze</p>
                             </div>
                         ) : (
                             <div className="space-y-4">
                                 {analysisResults.map((res, i) => (
                                     <div key={i} className="bg-white dark:bg-slate-900 p-4 rounded-xl border border-gray-100 dark:border-slate-800 shadow-sm animate-in slide-in-from-bottom-2 fade-in duration-500" style={{animationDelay: `${i * 100}ms`}}>
                                         <div className="flex justify-between items-start mb-2">
                                             <span className="font-bold text-indigo-600">{res.clauseId}</span>
                                             <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase ${res.status === 'COMPLIANT' ? 'bg-green-100 text-green-700' : res.status === 'OFI' ? 'bg-blue-100 text-blue-700' : 'bg-red-100 text-red-700'}`}>{res.status}</span>
                                         </div>
                                         <p className="text-sm text-slate-700 dark:text-slate-300 mb-2">{res.reason}</p>
                                         <p className="text-xs text-slate-500 dark:text-slate-400 italic mb-2 border-l-2 border-gray-200 pl-2">"{res.evidence}"</p>
                                         {res.suggestion && <div className="text-xs bg-indigo-50 dark:bg-indigo-900/20 p-2 rounded text-indigo-700 dark:text-indigo-300">💡 {res.suggestion}</div>}
                                     </div>
                                 ))}
                             </div>
                         )}
                    </div>
                </main>

                {isAnalyzeLoading && <AINeuralLoader message={loadingMessage} />}
                {showReleaseNotes && <ReleaseNotesModal isOpen={showReleaseNotes} onClose={() => setShowReleaseNotes(false)} />}
                {toastMessage && <Toast message={toastMessage} onClose={() => setToastMessage("")} />}
                <SnowOverlay />
           </div>
        </div>
    );
};

export default App;

